"""PropelPay v2.0 — Send. Sign. Get Paid."""
import logging, os
from contextlib import asynccontextmanager
from fastapi import FastAPI
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import HTMLResponse
from app.database import init_db
from app.api import auth, clients, proposals, invoices, dashboard, billing
from app.api.banks import router as banks_router

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(name)s: %(message)s")
logger = logging.getLogger(__name__)

@asynccontextmanager
async def lifespan(app: FastAPI):
    logger.info("PropelPay v2.0 starting...")
    await init_db()
    os.makedirs("uploads", exist_ok=True)
    yield

app = FastAPI(title="PropelPay API", version="2.0.0",
              docs_url="/docs", redoc_url="/redoc", lifespan=lifespan)

app.add_middleware(CORSMiddleware, allow_origins=["*"],
                   allow_credentials=True, allow_methods=["*"], allow_headers=["*"])

app.include_router(auth.router)
app.include_router(clients.router)
app.include_router(proposals.router)
app.include_router(invoices.router)
app.include_router(dashboard.router)
app.include_router(billing.router)
app.include_router(banks_router)

LANDING_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>PropelPay — Send. Sign. Get Paid.</title>\n<meta name="description" content="The all-in-one platform for freelancers and agencies to send AI-powered proposals, collect e-signatures, invoice clients and get paid automatically. Built for Africa, designed for the world.">\n<meta name="keywords" content="proposal software, invoice software, freelancer tools, get paid faster, paystack, e-signature, Africa">\n<meta property="og:title" content="PropelPay — Send. Sign. Get Paid.">\n<meta property="og:description" content="AI proposals + e-signatures + smart invoicing + auto payment chasing. One platform. Built for Africa.">\n<meta property="og:type" content="website">\n<link rel="icon" href="data:image/svg+xml,<svg xmlns=\'http://www.w3.org/2000/svg\' viewBox=\'0 0 100 100\'><text y=\'.9em\' font-size=\'90\'>⚡</text></svg>">\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\n:root{--brand:#6366f1;--brand2:#8b5cf6;--green:#10b981;--red:#ef4444;--yellow:#f59e0b;\n--bg:#0a0f1e;--card:#111827;--card2:#1e293b;--border:#1f2937;--text:#e2e8f0;--muted:#64748b;--white:#fff}\nhtml{scroll-behavior:smooth}\nbody{background:var(--bg);color:var(--text);font-family:\'Segoe UI\',system-ui,sans-serif;overflow-x:hidden}\na{color:inherit;text-decoration:none}\n.btn{display:inline-flex;align-items:center;gap:8px;padding:12px 24px;border-radius:10px;font-weight:700;font-size:15px;cursor:pointer;border:none;transition:.2s}\n.btn-primary{background:linear-gradient(135deg,var(--brand),var(--brand2));color:#fff}\n.btn-primary:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(99,102,241,.4)}\n.btn-outline{background:transparent;border:1.5px solid var(--border);color:var(--text)}\n.btn-outline:hover{border-color:var(--brand);color:var(--brand)}\n.btn-green{background:linear-gradient(135deg,var(--green),#059669);color:#fff}\n.btn-green:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(16,185,129,.4)}\n.container{max-width:1200px;margin:0 auto;padding:0 24px}\n/* NAV */\nnav{position:fixed;top:0;left:0;right:0;z-index:100;background:rgba(10,15,30,.9);backdrop-filter:blur(20px);border-bottom:1px solid var(--border)}\n.nav-inner{display:flex;align-items:center;justify-content:space-between;padding:16px 24px;max-width:1200px;margin:0 auto}\n.logo{font-size:22px;font-weight:900;background:linear-gradient(135deg,var(--brand),var(--brand2));-webkit-background-clip:text;-webkit-text-fill-color:transparent}\n.nav-links{display:flex;align-items:center;gap:32px}\n.nav-links a{color:var(--muted);font-size:14px;transition:.2s}\n.nav-links a:hover{color:var(--text)}\n.nav-cta{display:flex;gap:12px;align-items:center}\n/* HERO */\n.hero{min-height:100vh;display:flex;align-items:center;padding:120px 24px 80px;position:relative;overflow:hidden}\n.hero::before{content:\'\';position:absolute;top:-50%;left:-50%;width:200%;height:200%;\nbackground:radial-gradient(ellipse at 60% 40%,rgba(99,102,241,.12) 0%,transparent 60%),\n           radial-gradient(ellipse at 20% 80%,rgba(139,92,246,.08) 0%,transparent 50%);pointer-events:none}\n.hero-content{max-width:700px}\n.hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(99,102,241,.15);border:1px solid rgba(99,102,241,.3);\nborder-radius:50px;padding:6px 16px;font-size:13px;color:var(--brand);margin-bottom:24px}\n.hero h1{font-size:clamp(36px,6vw,72px);font-weight:900;line-height:1.05;margin-bottom:24px}\n.hero h1 span{background:linear-gradient(135deg,var(--brand),var(--brand2),var(--green));-webkit-background-clip:text;-webkit-text-fill-color:transparent}\n.hero p{font-size:19px;color:var(--muted);line-height:1.7;margin-bottom:40px;max-width:560px}\n.hero-cta{display:flex;gap:16px;flex-wrap:wrap;margin-bottom:48px}\n.hero-stats{display:flex;gap:40px;flex-wrap:wrap}\n.stat{display:flex;flex-direction:column}\n.stat-num{font-size:28px;font-weight:800;color:var(--white)}\n.stat-label{font-size:13px;color:var(--muted)}\n/* FEATURES */\n.section{padding:100px 0}\n.section-badge{display:inline-block;background:rgba(99,102,241,.15);border:1px solid rgba(99,102,241,.3);\nborder-radius:50px;padding:5px 14px;font-size:12px;color:var(--brand);text-transform:uppercase;letter-spacing:1.5px;margin-bottom:16px}\n.section-title{font-size:clamp(28px,4vw,48px);font-weight:800;margin-bottom:16px;line-height:1.15}\n.section-sub{font-size:17px;color:var(--muted);max-width:560px;line-height:1.7;margin-bottom:64px}\n.features-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:24px}\n.feature-card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:32px;transition:.2s;position:relative;overflow:hidden}\n.feature-card::before{content:\'\';position:absolute;inset:0;background:linear-gradient(135deg,rgba(99,102,241,.05),transparent);opacity:0;transition:.3s}\n.feature-card:hover{border-color:rgba(99,102,241,.4);transform:translateY(-4px)}\n.feature-card:hover::before{opacity:1}\n.feature-icon{width:52px;height:52px;background:linear-gradient(135deg,var(--brand),var(--brand2));border-radius:14px;\ndisplay:flex;align-items:center;justify-content:center;font-size:24px;margin-bottom:20px}\n.feature-title{font-size:18px;font-weight:700;margin-bottom:8px;color:var(--white)}\n.feature-desc{font-size:15px;color:var(--muted);line-height:1.7}\n/* HOW IT WORKS */\n.steps{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:0;position:relative}\n.step{text-align:center;padding:32px 24px}\n.step-num{width:56px;height:56px;background:linear-gradient(135deg,var(--brand),var(--brand2));border-radius:50%;\ndisplay:flex;align-items:center;justify-content:center;font-size:20px;font-weight:800;color:#fff;margin:0 auto 20px}\n.step-title{font-size:17px;font-weight:700;margin-bottom:8px;color:var(--white)}\n.step-desc{font-size:14px;color:var(--muted);line-height:1.7}\n/* PRICING */\n.pricing-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:24px;margin-top:64px}\n.price-card{background:var(--card);border:1px solid var(--border);border-radius:20px;padding:36px;position:relative}\n.price-card.popular{border-color:var(--brand);background:linear-gradient(135deg,rgba(99,102,241,.1),rgba(139,92,246,.05))}\n.popular-badge{position:absolute;top:-14px;left:50%;transform:translateX(-50%);\nbackground:linear-gradient(135deg,var(--brand),var(--brand2));color:#fff;font-size:12px;font-weight:700;\npadding:5px 18px;border-radius:50px;white-space:nowrap}\n.plan-name{font-size:14px;text-transform:uppercase;letter-spacing:1.5px;color:var(--muted);margin-bottom:8px}\n.plan-price{font-size:42px;font-weight:900;color:var(--white);margin-bottom:4px}\n.plan-price span{font-size:18px;font-weight:400;color:var(--muted)}\n.plan-period{font-size:13px;color:var(--muted);margin-bottom:24px}\n.plan-features{list-style:none;margin-bottom:32px}\n.plan-features li{display:flex;align-items:center;gap:10px;padding:8px 0;font-size:14px;color:var(--text);border-bottom:1px solid rgba(255,255,255,.05)}\n.plan-features li::before{content:\'✓\';color:var(--green);font-weight:800;flex-shrink:0}\n/* TESTIMONIALS */\n.testimonials{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:24px}\n.testimonial{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:28px}\n.t-stars{color:var(--yellow);font-size:16px;margin-bottom:12px}\n.t-text{font-size:15px;line-height:1.7;color:var(--text);margin-bottom:20px;font-style:italic}\n.t-author{display:flex;align-items:center;gap:12px}\n.t-avatar{width:40px;height:40px;background:linear-gradient(135deg,var(--brand),var(--brand2));border-radius:50%;\ndisplay:flex;align-items:center;justify-content:center;font-weight:700;color:#fff;font-size:16px}\n.t-name{font-size:14px;font-weight:700;color:var(--white)}\n.t-role{font-size:12px;color:var(--muted)}\n/* FAQ */\n.faq{max-width:780px;margin:64px auto 0}\n.faq-item{border-bottom:1px solid var(--border);overflow:hidden}\n.faq-q{width:100%;background:transparent;border:none;color:var(--text);font-size:16px;font-weight:600;\npadding:20px 0;text-align:left;cursor:pointer;display:flex;justify-content:space-between;align-items:center}\n.faq-q:hover{color:var(--brand)}\n.faq-a{font-size:14px;color:var(--muted);line-height:1.8;padding:0 0 20px;display:none}\n.faq-item.open .faq-a{display:block}\n.faq-item.open .faq-icon{transform:rotate(45deg)}\n.faq-icon{transition:.2s;font-size:20px;color:var(--muted)}\n/* CTA SECTION */\n.cta-section{background:linear-gradient(135deg,rgba(99,102,241,.15),rgba(139,92,246,.1));\nborder:1px solid rgba(99,102,241,.2);border-radius:24px;padding:72px 48px;text-align:center;margin:80px 0}\n/* FOOTER */\nfooter{background:var(--card);border-top:1px solid var(--border);padding:64px 0 32px}\n.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:48px;margin-bottom:48px}\n.footer-brand .logo{font-size:20px;display:block;margin-bottom:12px}\n.footer-brand p{font-size:14px;color:var(--muted);line-height:1.8;max-width:260px}\n.footer-col h4{font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:1.5px;color:var(--muted);margin-bottom:16px}\n.footer-col a{display:block;font-size:14px;color:var(--muted);margin-bottom:10px;transition:.2s}\n.footer-col a:hover{color:var(--brand)}\n.footer-bottom{border-top:1px solid var(--border);padding-top:24px;display:flex;justify-content:space-between;align-items:center;flex-wrap:gap:16px}\n.footer-bottom p{font-size:13px;color:var(--muted)}\n/* MODAL */\n.modal-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.7);backdrop-filter:blur(8px);z-index:1000;align-items:center;justify-content:center;padding:24px}\n.modal-overlay.open{display:flex}\n.modal{background:var(--card);border:1px solid var(--border);border-radius:20px;padding:40px;width:100%;max-width:480px;position:relative}\n.modal h2{font-size:22px;font-weight:800;margin-bottom:4px;color:var(--white)}\n.modal p{font-size:14px;color:var(--muted);margin-bottom:28px}\n.close-btn{position:absolute;top:16px;right:16px;background:transparent;border:none;color:var(--muted);font-size:22px;cursor:pointer}\n.form-group{margin-bottom:18px}\n.form-group label{display:block;font-size:13px;font-weight:600;color:var(--muted);margin-bottom:6px}\n.form-group input,.form-group select{width:100%;background:var(--card2);border:1px solid var(--border);border-radius:10px;\npadding:12px 16px;color:var(--text);font-size:14px;outline:none;transition:.2s}\n.form-group input:focus,.form-group select:focus{border-color:var(--brand)}\n.form-err{color:var(--red);font-size:13px;margin-top:6px;display:none}\n.form-row{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n.tabs{display:flex;border-bottom:1px solid var(--border);margin-bottom:28px}\n.tab-btn{flex:1;background:transparent;border:none;color:var(--muted);font-size:15px;font-weight:600;padding:12px;cursor:pointer;transition:.2s;border-bottom:2px solid transparent}\n.tab-btn.active{color:var(--brand);border-bottom-color:var(--brand)}\n.spinner{display:none;width:18px;height:18px;border:2px solid rgba(255,255,255,.3);border-top-color:#fff;border-radius:50%;animation:spin .6s linear infinite}\n@keyframes spin{to{transform:rotate(360deg)}}\n@media(max-width:768px){\n  .nav-links{display:none}.footer-grid{grid-template-columns:1fr 1fr}\n  .hero h1{font-size:36px}.cta-section{padding:48px 24px}\n  .form-row{grid-template-columns:1fr}\n}\n</style>\n</head>\n<body>\n\n<!-- NAV -->\n<nav>\n<div class="nav-inner">\n  <span class="logo">⚡ PropelPay</span>\n  <div class="nav-links">\n    <a href="#features">Features</a>\n    <a href="#how-it-works">How It Works</a>\n    <a href="#pricing">Pricing</a>\n    <a href="#faq">FAQ</a>\n  </div>\n  <div class="nav-cta">\n    <button class="btn btn-outline" style="padding:9px 18px;font-size:14px" onclick="openAuth(\'login\')">Log In</button>\n    <button class="btn btn-primary" style="padding:9px 18px;font-size:14px" onclick="openAuth(\'register\')">Start Free →</button>\n  </div>\n</div>\n</nav>\n\n<!-- HERO -->\n<section class="hero">\n<div class="container">\n<div class="hero-content">\n  <div class="hero-badge">🚀 Built for African freelancers &amp; agencies</div>\n  <h1>Stop Chasing.<br><span>Start Getting Paid.</span></h1>\n  <p>Write AI proposals in 30 seconds, collect e-signatures, send invoices and let PropelPay automatically chase your clients for payment. While you sleep.</p>\n  <div class="hero-cta">\n    <button class="btn btn-primary" style="padding:16px 32px;font-size:16px" onclick="openAuth(\'register\')">Start for Free — No Credit Card ⚡</button>\n    <button class="btn btn-outline" style="padding:16px 32px;font-size:16px" onclick="scrollTo(\'#how-it-works\')">See How It Works</button>\n  </div>\n  <div class="hero-stats">\n    <div class="stat"><span class="stat-num">$1.5T</span><span class="stat-label">Lost in unpaid invoices globally/yr</span></div>\n    <div class="stat"><span class="stat-num">10hrs</span><span class="stat-label">Saved per month per user</span></div>\n    <div class="stat"><span class="stat-num">43%→</span><span class="stat-label">Avg proposal close rate improvement</span></div>\n  </div>\n</div>\n</div>\n</section>\n\n<!-- FEATURES -->\n<section class="section" id="features">\n<div class="container">\n  <div class="section-badge">Everything You Need</div>\n  <div class="section-title">One platform. Every tool you need<br>to get paid faster.</div>\n  <div class="section-sub">Stop switching between 5 different tools. PropelPay combines proposals, contracts, invoicing and automated follow-ups — all powered by AI.</div>\n  <div class="features-grid">\n    <div class="feature-card">\n      <div class="feature-icon">🤖</div>\n      <div class="feature-title">AI Proposal Writer</div>\n      <div class="feature-desc">Describe your project in plain English. Our AI writes a complete, professional proposal with pricing, scope, timeline and terms in under 30 seconds.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">✍️</div>\n      <div class="feature-title">E-Signature Built In</div>\n      <div class="feature-desc">Clients sign proposals directly from their phone or browser. No printing, no scanning. Legally binding with IP logging and timestamp.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">🧾</div>\n      <div class="feature-title">Smart Invoicing</div>\n      <div class="feature-desc">Create professional invoices in seconds. Add line items, apply tax and discounts, set due dates. Beautiful PDF sent directly to your client.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">💳</div>\n      <div class="feature-title">Paystack &amp; Bank Transfer</div>\n      <div class="feature-desc">Accept Paystack payments directly on invoices. Or display your bank details for instant transfers. Money hits your account automatically.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">🔁</div>\n      <div class="feature-title">Auto Payment Reminders</div>\n      <div class="feature-desc">AI writes escalating reminder emails for overdue invoices. From friendly to firm to urgent — sent automatically so you don\'t have to chase.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">📊</div>\n      <div class="feature-title">Revenue Dashboard</div>\n      <div class="feature-desc">See exactly what you\'ve earned, what\'s pending, and what\'s overdue. AI insights tell you how to improve your collection rate this month.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">👥</div>\n      <div class="feature-title">Client CRM</div>\n      <div class="feature-desc">Keep all your client contacts organized. Full history of proposals and invoices per client. Never lose track of a deal again.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">🌍</div>\n      <div class="feature-title">Multi-Currency</div>\n      <div class="feature-desc">Bill in NGN, USD, GBP, EUR or any currency. Serve clients in Nigeria, UK, US or anywhere in the world with the same account.</div>\n    </div>\n    <div class="feature-card">\n      <div class="feature-icon">🔗</div>\n      <div class="feature-title">Public Payment Links</div>\n      <div class="feature-desc">Every invoice gets a unique shareable link. Share on WhatsApp, email or Telegram. Client pays in 2 clicks without signing up.</div>\n    </div>\n  </div>\n</div>\n</section>\n\n<!-- HOW IT WORKS -->\n<section class="section" id="how-it-works" style="background:var(--card2);border-top:1px solid var(--border);border-bottom:1px solid var(--border)">\n<div class="container">\n  <div style="text-align:center;margin-bottom:64px">\n    <div class="section-badge">Simple Process</div>\n    <div class="section-title">From project to payment in 4 steps</div>\n  </div>\n  <div class="steps">\n    <div class="step">\n      <div class="step-num">1</div>\n      <div class="step-title">Add Your Client</div>\n      <div class="step-desc">Save client name, email and company. Takes 30 seconds. PropelPay remembers everything.</div>\n    </div>\n    <div class="step">\n      <div class="step-num">2</div>\n      <div class="step-title">AI Writes Your Proposal</div>\n      <div class="step-desc">Tell the AI your project scope. It writes a full professional proposal with pricing. You review and send.</div>\n    </div>\n    <div class="step">\n      <div class="step-num">3</div>\n      <div class="step-title">Client Signs Online</div>\n      <div class="step-desc">Client receives a link, reads the proposal on their phone and signs with one tap. You get notified instantly.</div>\n    </div>\n    <div class="step">\n      <div class="step-num">4</div>\n      <div class="step-title">Get Paid Automatically</div>\n      <div class="step-desc">Invoice is sent. If client delays, PropelPay sends AI-written reminders automatically until you\'re paid.</div>\n    </div>\n  </div>\n</div>\n</section>\n\n<!-- PRICING -->\n<section class="section" id="pricing">\n<div class="container" style="text-align:center">\n  <div class="section-badge">Fair Pricing</div>\n  <div class="section-title">Start free. Upgrade when you\'re ready.</div>\n  <div class="section-sub" style="margin:0 auto 0">Priced for African freelancers. No hidden fees. Cancel anytime.</div>\n  <div class="pricing-grid">\n    <div class="price-card">\n      <div class="plan-name">Free</div>\n      <div class="plan-price">₦0<span></span></div>\n      <div class="plan-period">Forever free</div>\n      <ul class="plan-features">\n        <li>3 proposals/month</li>\n        <li>5 invoices/month</li>\n        <li>5 clients</li>\n        <li>3 AI drafts</li>\n        <li>E-signatures</li>\n        <li>Paystack payments</li>\n      </ul>\n      <button class="btn btn-outline" style="width:100%;justify-content:center" onclick="openAuth(\'register\')">Get Started Free</button>\n    </div>\n    <div class="price-card popular">\n      <div class="popular-badge">⚡ Most Popular</div>\n      <div class="plan-name">Solo</div>\n      <div class="plan-price">₦9,900<span></span></div>\n      <div class="plan-period">per month · ~$15 USD</div>\n      <ul class="plan-features">\n        <li>50 proposals/month</li>\n        <li>100 invoices/month</li>\n        <li>50 clients</li>\n        <li>50 AI drafts</li>\n        <li>Auto payment reminders</li>\n        <li>Priority email support</li>\n      </ul>\n      <button class="btn btn-primary" style="width:100%;justify-content:center" onclick="openAuth(\'register\')">Start Solo Plan →</button>\n    </div>\n    <div class="price-card">\n      <div class="plan-name">Agency</div>\n      <div class="plan-price">₦24,900<span></span></div>\n      <div class="plan-period">per month · ~$29 USD</div>\n      <ul class="plan-features">\n        <li>Unlimited proposals</li>\n        <li>Unlimited invoices</li>\n        <li>Unlimited clients</li>\n        <li>Unlimited AI drafts</li>\n        <li>White-label PDFs</li>\n        <li>API access</li>\n        <li>Priority support</li>\n      </ul>\n      <button class="btn btn-outline" style="width:100%;justify-content:center" onclick="openAuth(\'register\')">Start Agency Plan</button>\n    </div>\n    <div class="price-card">\n      <div class="plan-name">Enterprise</div>\n      <div class="plan-price">₦79,900<span></span></div>\n      <div class="plan-period">per month · ~$79 USD</div>\n      <ul class="plan-features">\n        <li>Everything in Agency</li>\n        <li>Custom branding</li>\n        <li>Dedicated support</li>\n        <li>Custom integrations</li>\n        <li>SLA guarantee</li>\n        <li>Team accounts</li>\n      </ul>\n      <button class="btn btn-outline" style="width:100%;justify-content:center" onclick="openAuth(\'register\')">Contact Sales</button>\n    </div>\n  </div>\n</div>\n</section>\n\n<!-- TESTIMONIALS -->\n<section class="section" style="background:var(--card2);border-top:1px solid var(--border);border-bottom:1px solid var(--border)">\n<div class="container">\n  <div style="text-align:center;margin-bottom:64px">\n    <div class="section-badge">Social Proof</div>\n    <div class="section-title">Freelancers are already getting paid faster</div>\n  </div>\n  <div class="testimonials">\n    <div class="testimonial">\n      <div class="t-stars">★★★★★</div>\n      <div class="t-text">"I used to spend 3 hours writing proposals. Now PropelPay AI does it in 30 seconds and my close rate went from 30% to 65%. This tool literally makes me money."</div>\n      <div class="t-author"><div class="t-avatar">A</div><div><div class="t-name">Adaeze Okafor</div><div class="t-role">UI/UX Designer, Lagos</div></div></div>\n    </div>\n    <div class="testimonial">\n      <div class="t-stars">★★★★★</div>\n      <div class="t-text">"I had ₦840,000 sitting in overdue invoices. PropelPay\'s automatic reminders recovered ₦620,000 in 2 weeks without me sending a single message myself."</div>\n      <div class="t-author"><div class="t-avatar">K</div><div><div class="t-name">Kwame Asante</div><div class="t-role">Marketing Agency Owner, Accra</div></div></div>\n    </div>\n    <div class="testimonial">\n      <div class="t-stars">★★★★★</div>\n      <div class="t-text">"As a developer working with UK clients, PropelPay lets me invoice in GBP and accept Paystack in Nigeria. The e-signature feature makes contracts seamless."</div>\n      <div class="t-author"><div class="t-avatar">T</div><div><div class="t-name">Tunde Adeleke</div><div class="t-role">Fullstack Developer, Abuja</div></div></div>\n    </div>\n  </div>\n</div>\n</section>\n\n<!-- FAQ -->\n<section class="section" id="faq">\n<div class="container" style="text-align:center">\n  <div class="section-badge">FAQ</div>\n  <div class="section-title">Frequently Asked Questions</div>\n  <div class="faq">\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">Is PropelPay really free to start? <span class="faq-icon">+</span></button>\n      <div class="faq-a">Yes — completely free, no credit card needed. You get 3 proposals, 5 invoices, 5 clients and 3 AI drafts per month. Upgrade only when you need more.</div>\n    </div>\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">How does the AI proposal writer work? <span class="faq-icon">+</span></button>\n      <div class="faq-a">You describe your service, scope and client name. Our AI (powered by Groq/Llama) writes a complete professional proposal with executive summary, scope of work, deliverables, timeline, pricing and terms. You can edit anything before sending.</div>\n    </div>\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">Are e-signatures legally binding? <span class="faq-icon">+</span></button>\n      <div class="faq-a">Yes. PropelPay captures the signer\'s name, email, IP address, timestamp and browser fingerprint. This creates an audit trail that is legally binding in Nigeria and most countries under electronic signature laws.</div>\n    </div>\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">How does automatic payment chasing work? <span class="faq-icon">+</span></button>\n      <div class="faq-a">When an invoice is overdue, PropelPay sends AI-written reminder emails to your client. The tone escalates from friendly to firm to urgent the longer it\'s overdue. You can also manually trigger reminders anytime from your dashboard.</div>\n    </div>\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">Can my clients pay without signing up? <span class="faq-icon">+</span></button>\n      <div class="faq-a">Yes. Every invoice gets a unique public link. Your client opens it, sees the invoice and pays directly via Paystack — no account needed. You can also share the link on WhatsApp or any messaging app.</div>\n    </div>\n    <div class="faq-item">\n      <button class="faq-q" onclick="toggleFaq(this)">What currencies are supported? <span class="faq-icon">+</span></button>\n      <div class="faq-a">You can invoice in any currency — NGN, USD, GBP, EUR, GHS, KES and more. Paystack payments work in NGN, USD, GBP and EUR. For other currencies, bank transfer details are displayed automatically.</div>\n    </div>\n  </div>\n</div>\n</section>\n\n<!-- FINAL CTA -->\n<section class="section">\n<div class="container">\n  <div class="cta-section">\n    <div style="font-size:48px;margin-bottom:16px">⚡</div>\n    <h2 style="font-size:42px;font-weight:900;margin-bottom:16px;color:var(--white)">Stop losing money to late payments.</h2>\n    <p style="font-size:18px;color:var(--muted);max-width:480px;margin:0 auto 40px;line-height:1.7">Join thousands of freelancers and agencies who send faster proposals and collect payments automatically with PropelPay.</p>\n    <button class="btn btn-primary" style="padding:18px 40px;font-size:17px" onclick="openAuth(\'register\')">Start for Free — Takes 60 Seconds →</button>\n    <p style="margin-top:16px;font-size:13px;color:var(--muted)">No credit card · Free forever plan · Setup in 60 seconds</p>\n  </div>\n</div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n<div class="container">\n  <div class="footer-grid">\n    <div class="footer-brand">\n      <span class="logo">⚡ PropelPay</span>\n      <p>The all-in-one platform for freelancers and agencies to send proposals, collect signatures and get paid faster.</p>\n    </div>\n    <div class="footer-col">\n      <h4>Product</h4>\n      <a href="#features">Features</a>\n      <a href="#pricing">Pricing</a>\n      <a href="#how-it-works">How It Works</a>\n      <a href="/docs">API Docs</a>\n    </div>\n    <div class="footer-col">\n      <h4>Use Cases</h4>\n      <a href="#">Freelancers</a>\n      <a href="#">Agencies</a>\n      <a href="#">Consultants</a>\n      <a href="#">Small Business</a>\n    </div>\n    <div class="footer-col">\n      <h4>Company</h4>\n      <a href="#">About</a>\n      <a href="#">Privacy Policy</a>\n      <a href="#">Terms of Service</a>\n      <a href="#">Contact</a>\n    </div>\n  </div>\n  <div class="footer-bottom">\n    <p>© 2026 PropelPay. Built with ❤️ for African creators.</p>\n    <p>Powered by Paystack · AI by Groq</p>\n  </div>\n</div>\n</footer>\n\n<!-- AUTH MODAL -->\n<div class="modal-overlay" id="authModal">\n<div class="modal">\n  <button class="close-btn" onclick="closeAuth()">×</button>\n  <div class="tabs">\n    <button class="tab-btn active" id="loginTab" onclick="switchTab(\'login\')">Log In</button>\n    <button class="tab-btn" id="registerTab" onclick="switchTab(\'register\')">Sign Up Free</button>\n  </div>\n  <!-- LOGIN FORM -->\n  <div id="loginForm">\n    <h2>Welcome back 👋</h2>\n    <p>Log in to your PropelPay account</p>\n    <div class="form-group"><label>Email</label><input type="email" id="loginEmail" placeholder="you@example.com"></div>\n    <div class="form-group"><label>Password</label><input type="password" id="loginPassword" placeholder="••••••••"></div>\n    <div class="form-err" id="loginErr"></div>\n    <button class="btn btn-primary" style="width:100%;justify-content:center;margin-top:8px" onclick="doLogin()" id="loginBtn">\n      <span class="spinner" id="loginSpinner"></span>Log In →\n    </button>\n  </div>\n  <!-- REGISTER FORM -->\n  <div id="registerForm" style="display:none">\n    <h2>Create your account 🚀</h2>\n    <p>Free forever. No credit card needed.</p>\n    <div class="form-row">\n      <div class="form-group"><label>Your Name</label><input type="text" id="regName" placeholder="Tunde Adeleke"></div>\n      <div class="form-group"><label>Business Name</label><input type="text" id="regBiz" placeholder="TechStudio NG"></div>\n    </div>\n    <div class="form-group"><label>Email</label><input type="email" id="regEmail" placeholder="you@example.com"></div>\n    <div class="form-row">\n      <div class="form-group"><label>Password</label><input type="password" id="regPass" placeholder="Min 8 characters"></div>\n      <div class="form-group"><label>Currency</label>\n        <select id="regCurrency"><option value="NGN">NGN — Nigerian Naira</option><option value="USD">USD — US Dollar</option><option value="GBP">GBP — British Pound</option><option value="EUR">EUR — Euro</option><option value="GHS">GHS — Ghanaian Cedi</option><option value="KES">KES — Kenyan Shilling</option></select>\n      </div>\n    </div>\n    <div class="form-err" id="regErr"></div>\n    <button class="btn btn-green" style="width:100%;justify-content:center;margin-top:8px" onclick="doRegister()" id="regBtn">\n      <span class="spinner" id="regSpinner"></span>Create Free Account →\n    </button>\n    <p style="font-size:12px;color:var(--muted);text-align:center;margin-top:12px">By signing up you agree to our Terms of Service and Privacy Policy</p>\n  </div>\n</div>\n</div>\n\n<script>\nconst API = window.location.origin;\n\nfunction openAuth(tab){ document.getElementById(\'authModal\').classList.add(\'open\'); switchTab(tab) }\nfunction closeAuth(){ document.getElementById(\'authModal\').classList.remove(\'open\') }\nfunction switchTab(t){\n  document.getElementById(\'loginForm\').style.display = t===\'login\'?\'block\':\'none\';\n  document.getElementById(\'registerForm\').style.display = t===\'register\'?\'block\':\'none\';\n  document.getElementById(\'loginTab\').classList.toggle(\'active\',t===\'login\');\n  document.getElementById(\'registerTab\').classList.toggle(\'active\',t===\'register\');\n}\nfunction scrollTo(sel){ document.querySelector(sel)?.scrollIntoView({behavior:\'smooth\'}) }\nfunction toggleFaq(btn){ btn.closest(\'.faq-item\').classList.toggle(\'open\') }\n\nfunction showErr(id,msg){ const e=document.getElementById(id); e.textContent=msg; e.style.display=\'block\' }\nfunction hideErr(id){ document.getElementById(id).style.display=\'none\' }\nfunction setLoading(btnId, spinnerId, loading){\n  const btn=document.getElementById(btnId), sp=document.getElementById(spinnerId);\n  btn.disabled=loading; sp.style.display=loading?\'inline-block\':\'none\';\n}\n\nasync function doLogin(){\n  hideErr(\'loginErr\');\n  const email=document.getElementById(\'loginEmail\').value.trim();\n  const pass=document.getElementById(\'loginPassword\').value;\n  if(!email||!pass){ showErr(\'loginErr\',\'Please fill all fields\'); return; }\n  setLoading(\'loginBtn\',\'loginSpinner\',true);\n  try{\n    const r=await fetch(`${API}/auth/login`,{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},body:JSON.stringify({email,password:pass})});\n    const d=await r.json();\n    if(!r.ok){ showErr(\'loginErr\',d.detail||\'Login failed\'); return; }\n    localStorage.setItem(\'pp_token\',d.token);\n    localStorage.setItem(\'pp_user\',JSON.stringify(d.user));\n    window.location.href=\'/dashboard\';\n  }catch(e){ showErr(\'loginErr\',\'Network error. Please try again.\'); }\n  finally{ setLoading(\'loginBtn\',\'loginSpinner\',false); }\n}\n\nasync function doRegister(){\n  hideErr(\'regErr\');\n  const name=document.getElementById(\'regName\').value.trim();\n  const biz=document.getElementById(\'regBiz\').value.trim();\n  const email=document.getElementById(\'regEmail\').value.trim();\n  const pass=document.getElementById(\'regPass\').value;\n  const currency=document.getElementById(\'regCurrency\').value;\n  if(!name||!email||!pass){ showErr(\'regErr\',\'Please fill all required fields\'); return; }\n  if(pass.length<8){ showErr(\'regErr\',\'Password must be at least 8 characters\'); return; }\n  setLoading(\'regBtn\',\'regSpinner\',true);\n  try{\n    const r=await fetch(`${API}/auth/register`,{method:\'POST\',headers:{\'Content-Type\':\'application/json\'},\n      body:JSON.stringify({name,email,password:pass,business_name:biz||name,currency})});\n    const d=await r.json();\n    if(!r.ok){ showErr(\'regErr\',d.detail||\'Registration failed\'); return; }\n    localStorage.setItem(\'pp_token\',d.token);\n    localStorage.setItem(\'pp_user\',JSON.stringify(d.user));\n    window.location.href=\'/dashboard\';\n  }catch(e){ showErr(\'regErr\',\'Network error. Please try again.\'); }\n  finally{ setLoading(\'regBtn\',\'regSpinner\',false); }\n}\n\n// Close modal on overlay click\ndocument.getElementById(\'authModal\').addEventListener(\'click\',function(e){ if(e.target===this)closeAuth(); });\n// Enter key support\ndocument.addEventListener(\'keydown\',e=>{ if(e.key===\'Escape\')closeAuth(); });\n// Check if already logged in\nif(localStorage.getItem(\'pp_token\') && window.location.pathname===\'/\'){\n  // Don\'t auto-redirect on landing page\n}\n</script>\n</body>\n</html>\n'
DASHBOARD_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">\n<title>PropelPay Dashboard</title>\n<link rel="icon" href="data:image/svg+xml,<svg xmlns=\'http://www.w3.org/2000/svg\' viewBox=\'0 0 100 100\'><text y=\'.9em\' font-size=\'90\'>⚡</text></svg>">\n<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\n:root{--brand:#6366f1;--brand2:#8b5cf6;--green:#10b981;--red:#ef4444;--yellow:#f59e0b;--blue:#3b82f6;\n--bg:#070d1a;--sidebar:#0a0f1e;--card:#0d1526;--card2:#111f38;--border:#1a2845;\n--text:#e2e8f0;--muted:#64748b;--white:#fff;--grad:linear-gradient(135deg,var(--brand),var(--brand2))}\nbody{background:var(--bg);color:var(--text);font-family:\'Segoe UI\',system-ui,sans-serif;display:flex;height:100vh;overflow:hidden}\n\n/* ── SIDEBAR ── */\n.sidebar{width:244px;background:var(--sidebar);border-right:1px solid var(--border);display:flex;flex-direction:column;flex-shrink:0;position:relative;z-index:10}\n.sidebar::before{content:\'\';position:absolute;top:0;left:0;right:0;height:1px;background:var(--grad);opacity:.6}\n.sidebar-logo{padding:22px 20px;border-bottom:1px solid var(--border)}\n.logo{font-size:19px;font-weight:900;background:var(--grad);-webkit-background-clip:text;-webkit-text-fill-color:transparent}\n.logo-sub{font-size:10px;color:var(--muted);letter-spacing:1px;margin-top:2px}\n.nav-section{padding:8px 12px 4px;font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:1.2px;margin-top:8px}\n.nav-items{padding:8px;flex:1;overflow-y:auto}\n.nav-item{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:10px;font-size:13px;color:var(--muted);cursor:pointer;transition:.15s;margin-bottom:2px;position:relative}\n.nav-item:hover{background:rgba(99,102,241,.12);color:var(--text)}\n.nav-item.active{background:rgba(99,102,241,.18);color:var(--brand);font-weight:600}\n.nav-item.active::before{content:\'\';position:absolute;left:0;top:20%;bottom:20%;width:3px;background:var(--brand);border-radius:0 3px 3px 0}\n.nav-icon{font-size:15px;width:20px;text-align:center}\n.nav-badge{margin-left:auto;background:var(--red);color:#fff;font-size:10px;padding:2px 6px;border-radius:20px;font-weight:700}\n.sidebar-user{padding:14px 16px;border-top:1px solid var(--border)}\n.user-info{display:flex;align-items:center;gap:10px}\n.avatar{width:36px;height:36px;background:var(--grad);border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;flex-shrink:0;color:#fff}\n.user-name{font-size:13px;font-weight:700;color:var(--white)}\n.user-plan{font-size:10px;color:var(--muted)}\n\n/* ── MAIN ── */\n.main{flex:1;overflow-y:auto;display:flex;flex-direction:column;min-width:0}\n.topbar{background:var(--sidebar);border-bottom:1px solid var(--border);padding:16px 28px;display:flex;align-items:center;justify-content:space-between;flex-shrink:0;position:sticky;top:0;z-index:5}\n.topbar h1{font-size:19px;font-weight:800;color:var(--white)}\n.topbar-sub{font-size:12px;color:var(--muted);margin-top:1px}\n.topbar-actions{display:flex;gap:10px;align-items:center}\n\n/* ── BUTTONS ── */\n.btn{display:inline-flex;align-items:center;gap:6px;padding:9px 18px;border-radius:9px;font-weight:600;font-size:13px;cursor:pointer;border:none;transition:.15s;text-decoration:none}\n.btn:disabled{opacity:.5;cursor:not-allowed}\n.btn-primary{background:var(--grad);color:#fff;box-shadow:0 0 20px rgba(99,102,241,.25)}\n.btn-primary:hover{opacity:.88;transform:translateY(-1px)}\n.btn-outline{background:transparent;border:1px solid var(--border);color:var(--text)}\n.btn-outline:hover{border-color:var(--brand);color:var(--brand)}\n.btn-green{background:linear-gradient(135deg,var(--green),#059669);color:#fff}\n.btn-green:hover{opacity:.88}\n.btn-red{background:rgba(239,68,68,.15);color:var(--red);border:1px solid rgba(239,68,68,.3)}\n.btn-red:hover{background:var(--red);color:#fff}\n.btn-yellow{background:rgba(245,158,11,.15);color:var(--yellow);border:1px solid rgba(245,158,11,.3)}\n.btn-sm{padding:6px 12px;font-size:12px;border-radius:7px}\n.btn-xs{padding:4px 9px;font-size:11px;border-radius:6px}\n.btn-icon{padding:7px;border-radius:8px}\n\n.content{padding:24px 28px;flex:1}\n.page{display:none}.page.active{display:block}\n\n/* ── STATS ── */\n.stats-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:22px}\n.stat-card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:20px;position:relative;overflow:hidden;transition:.2s}\n.stat-card:hover{border-color:rgba(99,102,241,.4);transform:translateY(-1px)}\n.stat-card::after{content:\'\';position:absolute;top:0;right:0;width:60px;height:60px;background:var(--grad);opacity:.05;border-radius:0 14px 0 60px}\n.stat-label{font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.9px;margin-bottom:10px;font-weight:600}\n.stat-value{font-size:24px;font-weight:900;color:var(--white);line-height:1}\n.stat-change{font-size:11px;margin-top:6px;display:flex;align-items:center;gap:4px}\n.stat-icon{position:absolute;top:18px;right:18px;font-size:20px;opacity:.3}\n.green{color:var(--green)}.red{color:var(--red)}.yellow{color:var(--yellow)}.blue{color:var(--blue)}\n\n/* ── SKELETON ── */\n.skeleton{background:linear-gradient(90deg,var(--border) 25%,var(--card2) 50%,var(--border) 75%);background-size:200% 100%;animation:shimmer 1.4s infinite;border-radius:6px}\n@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}\n.sk-line{height:14px;margin-bottom:8px}\n.sk-title{height:20px;width:60%}\n.sk-val{height:28px;width:40%}\n\n/* ── TABLE ── */\n.table-card{background:var(--card);border:1px solid var(--border);border-radius:14px;overflow:hidden;margin-bottom:18px}\n.table-header{padding:16px 20px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between}\n.table-header h3{font-size:14px;font-weight:700;color:var(--white)}\ntable{width:100%;border-collapse:collapse}\nth{padding:11px 18px;text-align:left;font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.8px;background:rgba(0,0,0,.2);border-bottom:1px solid var(--border);white-space:nowrap}\ntd{padding:13px 18px;font-size:13px;border-bottom:1px solid rgba(255,255,255,.04);transition:.1s}\ntr:last-child td{border-bottom:none}\ntr:hover td{background:rgba(99,102,241,.04)}\n.td-actions{display:flex;gap:6px;flex-wrap:nowrap}\n\n/* ── BADGES ── */\n.badge{display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:50px;font-size:11px;font-weight:700}\n.badge::before{content:\'\';width:5px;height:5px;border-radius:50%;background:currentColor}\n.badge-draft{background:rgba(100,116,139,.15);color:#94a3b8}\n.badge-sent{background:rgba(99,102,241,.15);color:#818cf8}\n.badge-viewed{background:rgba(245,158,11,.15);color:#fbbf24}\n.badge-paid{background:rgba(16,185,129,.15);color:#34d399}\n.badge-overdue{background:rgba(239,68,68,.15);color:#f87171}\n.badge-accepted{background:rgba(16,185,129,.15);color:#34d399}\n.badge-declined{background:rgba(239,68,68,.15);color:#f87171}\n.badge-queued{background:rgba(100,116,139,.15);color:#94a3b8}\n.badge-failed{background:rgba(239,68,68,.15);color:#f87171}\n.badge-cancelled{background:rgba(100,116,139,.15);color:#94a3b8}\n.badge-free{background:rgba(99,102,241,.1);color:var(--brand)}\n.badge-solo,.badge-pro{background:rgba(245,158,11,.15);color:#fbbf24}\n.badge-agency,.badge-enterprise{background:rgba(16,185,129,.15);color:#34d399}\n\n/* ── MODAL ── */\n.overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.75);backdrop-filter:blur(10px);z-index:1000;align-items:center;justify-content:center;padding:20px}\n.overlay.open{display:flex}\n.modal{background:var(--card);border:1px solid var(--border);border-radius:18px;padding:28px;width:100%;max-width:580px;max-height:90vh;overflow-y:auto;box-shadow:0 25px 80px rgba(0,0,0,.5)}\n.modal-lg{max-width:720px}\n.modal h2{font-size:17px;font-weight:800;margin-bottom:18px;color:var(--white)}\n\n/* ── FORMS ── */\n.form-group{margin-bottom:14px}\n.form-group label{display:block;font-size:11px;font-weight:700;color:var(--muted);margin-bottom:5px;text-transform:uppercase;letter-spacing:.8px}\n.form-group input,.form-group select,.form-group textarea{width:100%;background:var(--card2);border:1.5px solid var(--border);border-radius:9px;padding:10px 14px;color:var(--text);font-size:13px;outline:none;transition:.15s;font-family:inherit}\n.form-group input:focus,.form-group select:focus,.form-group textarea:focus{border-color:var(--brand);box-shadow:0 0 0 3px rgba(99,102,241,.1)}\n.form-group textarea{min-height:80px;resize:vertical}\n.form-group select option{background:var(--card)}\n.form-row{display:grid;grid-template-columns:1fr 1fr;gap:12px}\n.form-actions{display:flex;gap:10px;justify-content:flex-end;margin-top:20px}\n\n/* ── INVOICE ITEMS ── */\n.item-row{display:grid;grid-template-columns:3fr 1fr 1.5fr auto;gap:8px;align-items:center;margin-bottom:8px}\n.item-row input{background:var(--card2);border:1.5px solid var(--border);border-radius:8px;padding:8px 10px;color:var(--text);font-size:13px;outline:none;width:100%}\n.item-row input:focus{border-color:var(--brand)}\n.remove-btn{background:rgba(239,68,68,.12);color:var(--red);border:1px solid rgba(239,68,68,.2);border-radius:7px;padding:8px 10px;cursor:pointer;font-size:13px;transition:.15s}\n.remove-btn:hover{background:var(--red);color:#fff}\n\n/* ── AI RESULT ── */\n.ai-result{background:rgba(99,102,241,.08);border:1.5px solid rgba(99,102,241,.25);border-radius:11px;padding:16px;margin:12px 0;font-size:13px;line-height:1.75;color:var(--text);max-height:200px;overflow-y:auto}\n\n/* ── CHART ── */\n.chart-wrap{position:relative;height:180px;padding:8px 0}\n\n/* ── INSIGHT CARD ── */\n.insight-card{background:linear-gradient(135deg,rgba(99,102,241,.08),rgba(139,92,246,.04));border:1px solid rgba(99,102,241,.2);border-radius:14px;padding:20px}\n.insight-header{display:flex;align-items:center;gap:8px;margin-bottom:10px}\n.insight-header span{font-size:13px;font-weight:700;color:var(--white)}\n\n/* ── OVERVIEW GRID ── */\n.overview-grid{display:grid;grid-template-columns:1.5fr 1fr;gap:16px;margin-bottom:20px}\n\n/* ── ALERTS ── */\n.alert{padding:12px 16px;border-radius:9px;font-size:13px;margin-bottom:14px;display:flex;align-items:center;gap:8px;animation:slideDown .2s ease}\n@keyframes slideDown{from{opacity:0;transform:translateY(-8px)}to{opacity:1;transform:translateY(0)}}\n.alert-success{background:rgba(16,185,129,.1);border:1px solid rgba(16,185,129,.25);color:var(--green)}\n.alert-error{background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.25);color:var(--red)}\n.alert-info{background:rgba(99,102,241,.1);border:1px solid rgba(99,102,241,.25);color:#818cf8}\n.alert-warn{background:rgba(245,158,11,.1);border:1px solid rgba(245,158,11,.25);color:var(--yellow)}\n\n/* ── EMPTY STATE ── */\n.empty{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:64px 24px;text-align:center}\n.empty-icon{font-size:48px;margin-bottom:16px;opacity:.6}\n.empty h3{font-size:15px;font-weight:700;color:var(--white);margin-bottom:6px}\n.empty p{font-size:13px;color:var(--muted);max-width:280px;line-height:1.6;margin-bottom:20px}\n\n/* ── DIVIDER ── */\n.divider{height:1px;background:var(--border);margin:20px 0}\n\n/* ── EMAIL STATUS ── */\n.email-trail{background:var(--card2);border:1px solid var(--border);border-radius:10px;padding:12px 16px;margin-top:12px}\n.email-trail h4{font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.8px;margin-bottom:8px}\n.email-item{display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,.04);font-size:12px}\n.email-item:last-child{border-bottom:none}\n.email-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}\n\n/* ── BANK CARDS ── */\n.bank-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px;margin-bottom:16px}\n.bank-card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:16px;position:relative}\n.bank-card.primary{border-color:rgba(99,102,241,.4)}\n.bank-card-flag{font-size:20px;margin-bottom:8px}\n.bank-card-currency{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--brand);margin-bottom:4px}\n.bank-card-name{font-size:13px;font-weight:700;color:var(--white)}\n.bank-card-num{font-size:12px;color:var(--muted);margin-top:2px}\n.bank-card-badge{position:absolute;top:12px;right:12px}\n\n/* ── RESPONSIVE ── */\n@media(max-width:900px){\n  .sidebar{position:fixed;left:-244px;height:100vh;transition:.25s;z-index:100}\n  .sidebar.open{left:0}\n  .stats-grid{grid-template-columns:1fr 1fr}\n  .overview-grid{grid-template-columns:1fr}\n  .form-row{grid-template-columns:1fr}\n  .item-row{grid-template-columns:1fr 1fr;row-gap:6px}\n}\n</style>\n</head>\n<body>\n\n<!-- SIDEBAR -->\n<div class="sidebar" id="sidebar">\n  <div class="sidebar-logo">\n    <div class="logo">⚡ PropelPay</div>\n    <div class="logo-sub">DASHBOARD</div>\n  </div>\n  <div class="nav-items">\n    <div class="nav-section">Main</div>\n    <div class="nav-item active" onclick="showPage(\'overview\')"><span class="nav-icon">📊</span>Overview</div>\n    <div class="nav-item" onclick="showPage(\'proposals\')"><span class="nav-icon">📄</span>Proposals</div>\n    <div class="nav-item" onclick="showPage(\'invoices\')"><span class="nav-icon">🧾</span>Invoices</div>\n    <div class="nav-item" onclick="showPage(\'clients\')"><span class="nav-icon">👥</span>Clients</div>\n    <div class="nav-section">Account</div>\n    <div class="nav-item" onclick="showPage(\'settings\')"><span class="nav-icon">⚙️</span>Settings</div>\n  </div>\n  <div class="sidebar-user">\n    <div class="user-info">\n      <div class="avatar" id="sideAvatar">U</div>\n      <div><div class="user-name" id="sideUsername">Loading…</div>\n           <div class="user-plan" id="sidePlan">Free Plan</div></div>\n    </div>\n  </div>\n</div>\n\n<!-- MAIN -->\n<div class="main">\n<div class="topbar">\n  <div>\n    <h1 id="pageTitle">Overview</h1>\n    <div class="topbar-sub" id="pageDate"></div>\n  </div>\n  <div class="topbar-actions">\n    <button class="btn btn-primary" id="topbarAction" onclick="topbarActionFn()">+ New Invoice</button>\n    <button class="btn btn-outline btn-sm" onclick="logout()">Log Out</button>\n  </div>\n</div>\n<div class="content">\n\n<!-- ───────────── OVERVIEW ───────────── -->\n<div class="page active" id="page-overview">\n  <div id="alertBox"></div>\n  <div class="stats-grid" id="statsGrid">\n    <!-- Skeleton loaders -->\n    <div class="stat-card"><div class="stat-label skeleton sk-line" style="width:60%"></div><div class="stat-value skeleton sk-val" style="margin-top:10px"></div></div>\n    <div class="stat-card"><div class="stat-label skeleton sk-line" style="width:60%"></div><div class="stat-value skeleton sk-val" style="margin-top:10px"></div></div>\n    <div class="stat-card"><div class="stat-label skeleton sk-line" style="width:60%"></div><div class="stat-value skeleton sk-val" style="margin-top:10px"></div></div>\n    <div class="stat-card"><div class="stat-label skeleton sk-line" style="width:60%"></div><div class="stat-value skeleton sk-val" style="margin-top:10px"></div></div>\n  </div>\n  <div class="overview-grid">\n    <div class="table-card">\n      <div class="table-header"><h3>📈 Monthly Revenue</h3><span id="chartCurrency" style="font-size:12px;color:var(--muted)"></span></div>\n      <div style="padding:16px 20px"><div class="chart-wrap"><canvas id="revenueChart"></canvas></div></div>\n    </div>\n    <div class="insight-card">\n      <div class="insight-header">🤖 <span>AI Business Insights</span>\n        <button class="btn btn-sm btn-outline" style="margin-left:auto;font-size:11px" onclick="loadInsights(true)">Refresh</button>\n      </div>\n      <div id="aiInsights" style="font-size:13px;color:var(--muted);line-height:1.75">\n        <div class="skeleton sk-line"></div>\n        <div class="skeleton sk-line" style="width:85%"></div>\n        <div class="skeleton sk-line" style="width:70%"></div>\n      </div>\n    </div>\n  </div>\n  <div class="table-card">\n    <div class="table-header"><h3>⚡ Recent Activity</h3></div>\n    <table><thead><tr><th>Type</th><th>Description</th><th>Amount</th><th>Status</th><th>Date</th></tr></thead>\n    <tbody id="recentTable"><tr><td colspan="5"><div style="padding:16px"><div class="skeleton sk-line"></div><div class="skeleton sk-line" style="width:80%"></div><div class="skeleton sk-line" style="width:60%"></div></div></td></tr></tbody></table>\n  </div>\n</div>\n\n<!-- ───────────── PROPOSALS ───────────── -->\n<div class="page" id="page-proposals">\n  <div id="propAlert"></div>\n  <div class="table-card">\n    <div class="table-header">\n      <h3>📄 Proposals</h3>\n      <button class="btn btn-primary btn-sm" onclick="openNewProposal()">+ New Proposal</button>\n    </div>\n    <table><thead><tr><th>Title</th><th>Client</th><th>Amount</th><th>Status</th><th>Created</th><th>Actions</th></tr></thead>\n    <tbody id="proposalTable"><tr><td colspan="6"><div class="skeleton sk-line" style="margin:16px"></div></td></tr></tbody></table>\n  </div>\n</div>\n\n<!-- ───────────── INVOICES ───────────── -->\n<div class="page" id="page-invoices">\n  <div id="invAlert"></div>\n  <div class="table-card">\n    <div class="table-header">\n      <h3>🧾 Invoices</h3>\n      <div style="display:flex;gap:8px">\n        <select id="invFilter" class="btn btn-outline btn-sm" onchange="loadInvoices()" style="padding:6px 10px;border-radius:7px;background:var(--card2);color:var(--text)">\n          <option value="">All</option>\n          <option value="draft">Draft</option>\n          <option value="sent">Sent</option>\n          <option value="viewed">Viewed</option>\n          <option value="paid">Paid</option>\n          <option value="overdue">Overdue</option>\n        </select>\n        <button class="btn btn-primary btn-sm" onclick="openNewInvoice()">+ New Invoice</button>\n      </div>\n    </div>\n    <table><thead><tr><th>Invoice #</th><th>Client</th><th>Amount</th><th>Due</th><th>Status</th><th>Email</th><th>Actions</th></tr></thead>\n    <tbody id="invoiceTable"><tr><td colspan="7"><div class="skeleton sk-line" style="margin:16px"></div></td></tr></tbody></table>\n  </div>\n</div>\n\n<!-- ───────────── CLIENTS ───────────── -->\n<div class="page" id="page-clients">\n  <div id="clientAlert"></div>\n  <div class="table-card">\n    <div class="table-header">\n      <h3>👥 Clients</h3>\n      <button class="btn btn-primary btn-sm" onclick="openNewClient()">+ Add Client</button>\n    </div>\n    <table><thead><tr><th>Name</th><th>Email</th><th>Phone</th><th>Company</th><th>Added</th><th>Actions</th></tr></thead>\n    <tbody id="clientTable"><tr><td colspan="6"><div class="skeleton sk-line" style="margin:16px"></div></td></tr></tbody></table>\n  </div>\n</div>\n\n<!-- ───────────── SETTINGS ───────────── -->\n<div class="page" id="page-settings">\n  <div id="settingsAlert"></div>\n  <!-- Settings tabs -->\n  <div style="display:flex;gap:4px;margin-bottom:20px;background:var(--card);border:1px solid var(--border);border-radius:11px;padding:4px;width:fit-content">\n    <button class="btn btn-primary btn-sm" id="stab-profile" onclick="switchSettingsTab(\'profile\')">Profile</button>\n    <button class="btn btn-outline btn-sm" id="stab-banks" onclick="switchSettingsTab(\'banks\')">Bank Accounts</button>\n    <button class="btn btn-outline btn-sm" id="stab-plan" onclick="switchSettingsTab(\'plan\')">Plan & Billing</button>\n  </div>\n\n  <!-- Profile tab -->\n  <div id="settingsTab-profile">\n    <div class="table-card" style="padding:24px">\n      <h3 style="margin-bottom:18px;font-size:15px;font-weight:700;color:var(--white)">Business Profile</h3>\n      <div class="form-row">\n        <div class="form-group"><label>Full Name</label><input id="pName" placeholder="Your name"></div>\n        <div class="form-group"><label>Business Name</label><input id="pBusiness" placeholder="Company name"></div>\n      </div>\n      <div class="form-row">\n        <div class="form-group"><label>Phone</label><input id="pPhone" placeholder="+234..."></div>\n        <div class="form-group"><label>Country</label>\n          <select id="pCountry">\n            <option>Nigeria</option><option>Ghana</option><option>Kenya</option><option>South Africa</option>\n            <option>United States</option><option>United Kingdom</option><option>Canada</option><option>Other</option>\n          </select>\n        </div>\n      </div>\n      <div class="form-row">\n        <div class="form-group"><label>Default Currency</label>\n          <select id="pCurrency">\n            <option value="NGN">🇳🇬 NGN — Nigerian Naira</option>\n            <option value="GHS">🇬🇭 GHS — Ghanaian Cedi</option>\n            <option value="KES">🇰🇪 KES — Kenyan Shilling</option>\n            <option value="ZAR">🇿🇦 ZAR — South African Rand</option>\n            <option value="USD">🇺🇸 USD — US Dollar</option>\n            <option value="GBP">🇬🇧 GBP — British Pound</option>\n            <option value="EUR">🇪🇺 EUR — Euro</option>\n          </select>\n        </div>\n        <div class="form-group"><label>Email</label><input id="pEmail" disabled style="opacity:.5"></div>\n      </div>\n      <div style="display:flex;gap:10px;margin-top:8px">\n        <button class="btn btn-primary" onclick="saveProfile()">Save Profile</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- Bank Accounts tab -->\n  <div id="settingsTab-banks" style="display:none">\n    <div class="table-card" style="padding:24px">\n      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px">\n        <div>\n          <h3 style="font-size:15px;font-weight:700;color:var(--white)">Bank Accounts</h3>\n          <p style="font-size:12px;color:var(--muted);margin-top:3px">Add accounts for each currency you invoice in. Clients see the right bank on their invoice.</p>\n        </div>\n        <button class="btn btn-primary btn-sm" onclick="openAddBank()">+ Add Account</button>\n      </div>\n      <div id="bankGrid" class="bank-grid">\n        <div class="skeleton" style="height:100px;border-radius:12px"></div>\n        <div class="skeleton" style="height:100px;border-radius:12px"></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Plan tab -->\n  <div id="settingsTab-plan" style="display:none">\n    <div class="table-card" style="padding:24px">\n      <h3 style="margin-bottom:4px;font-size:15px;font-weight:700;color:var(--white)">Current Plan</h3>\n      <p id="planDesc" style="font-size:13px;color:var(--muted);margin-bottom:20px">Loading…</p>\n      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px">\n        <div class="stat-card" style="cursor:pointer;border-color:rgba(99,102,241,.3)" onclick="upgradePlan(\'solo\')">\n          <div class="stat-label">Solo</div>\n          <div class="stat-value" style="font-size:18px">₦9,900<span style="font-size:12px;color:var(--muted)">/mo</span></div>\n          <div style="font-size:11px;color:var(--muted);margin-top:6px">50 invoices · 50 proposals · AI drafts</div>\n        </div>\n        <div class="stat-card" style="cursor:pointer;border-color:rgba(16,185,129,.3)" onclick="upgradePlan(\'agency\')">\n          <div class="stat-label">Agency</div>\n          <div class="stat-value" style="font-size:18px">₦24,900<span style="font-size:12px;color:var(--muted)">/mo</span></div>\n          <div style="font-size:11px;color:var(--muted);margin-top:6px">Unlimited everything + team access</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n</div><!-- /content -->\n</div><!-- /main -->\n\n<!-- ═══════════════ MODALS ═══════════════ -->\n\n<!-- New Proposal -->\n<div class="overlay" id="proposalOverlay">\n  <div class="modal modal-lg">\n    <h2>📄 New Proposal</h2>\n    <div class="form-row">\n      <div class="form-group"><label>Client</label>\n        <select id="pClient"><option value="">— Select client —</option></select>\n      </div>\n      <div class="form-group"><label>Service Type</label>\n        <input id="pService" placeholder="e.g. Web Development, Brand Design…">\n      </div>\n    </div>\n    <div class="form-group"><label>Scope of Work</label>\n      <textarea id="pScope" rows="3" placeholder="Describe what you\'ll deliver…"></textarea>\n    </div>\n    <div class="form-row">\n      <div class="form-group"><label>Budget (optional)</label>\n        <input id="pBudget" placeholder="e.g. ₦500,000">\n      </div>\n      <div class="form-group"><label>Tone</label>\n        <select id="pTone"><option value="professional">Professional</option><option value="friendly">Friendly</option><option value="bold">Bold & Confident</option></select>\n      </div>\n    </div>\n    <button class="btn btn-primary" onclick="generateAIProposal()" id="aiGenBtn">✨ Generate with AI</button>\n    <div id="aiProposalResult" class="ai-result" style="display:none"></div>\n    <div class="form-actions">\n      <button class="btn btn-outline" onclick="closeModal(\'proposalOverlay\')">Cancel</button>\n      <button class="btn btn-green" onclick="saveAIProposal()" id="savePropBtn" disabled>Save Proposal</button>\n    </div>\n  </div>\n</div>\n\n<!-- New Invoice -->\n<div class="overlay" id="invoiceOverlay">\n  <div class="modal modal-lg">\n    <h2>🧾 New Invoice</h2>\n    <div class="form-row">\n      <div class="form-group"><label>Client</label>\n        <select id="iClient"><option value="">— Select client —</option></select>\n      </div>\n      <div class="form-group"><label>Title</label>\n        <input id="iTitle" placeholder="Invoice for Web Development…">\n      </div>\n    </div>\n    <div class="form-row">\n      <div class="form-group"><label>Currency</label>\n        <select id="iCurrency">\n          <option value="NGN">NGN</option><option value="USD">USD</option>\n          <option value="GBP">GBP</option><option value="EUR">EUR</option>\n          <option value="GHS">GHS</option><option value="KES">KES</option>\n        </select>\n      </div>\n      <div class="form-group"><label>Due Date</label>\n        <input type="date" id="iDue">\n      </div>\n    </div>\n    <div style="margin-bottom:10px">\n      <label style="font-size:11px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.8px;display:block;margin-bottom:8px">Line Items</label>\n      <div id="itemRows"></div>\n      <button class="btn btn-outline btn-sm" onclick="addItem()" style="margin-top:6px">+ Add Line Item</button>\n    </div>\n    <div class="form-row">\n      <div class="form-group"><label>Tax Rate (%)</label><input type="number" id="iTax" value="0" min="0" max="100" onchange="calcTotal()"></div>\n      <div class="form-group"><label>Discount (flat)</label><input type="number" id="iDiscount" value="0" min="0" onchange="calcTotal()"></div>\n    </div>\n    <div style="background:var(--card2);border-radius:10px;padding:14px;margin-bottom:12px;display:flex;justify-content:space-between;align-items:center">\n      <span style="font-size:13px;color:var(--muted)">Total</span>\n      <span style="font-size:20px;font-weight:800;color:var(--brand)" id="invTotal">—</span>\n    </div>\n    <div class="form-group"><label>Notes</label><textarea id="iNotes" rows="2" placeholder="Payment terms, thanks, etc…"></textarea></div>\n    <div class="form-actions">\n      <button class="btn btn-outline" onclick="closeModal(\'invoiceOverlay\')">Cancel</button>\n      <button class="btn btn-green" onclick="saveInvoice()">Create Invoice</button>\n    </div>\n  </div>\n</div>\n\n<!-- New Client -->\n<div class="overlay" id="clientOverlay">\n  <div class="modal">\n    <h2>👤 Add Client</h2>\n    <div class="form-row">\n      <div class="form-group"><label>Name</label><input id="cName" placeholder="Full name"></div>\n      <div class="form-group"><label>Email</label><input id="cEmail" type="email" placeholder="email@example.com"></div>\n    </div>\n    <div class="form-row">\n      <div class="form-group"><label>Phone</label><input id="cPhone" placeholder="+234…"></div>\n      <div class="form-group"><label>Company</label><input id="cCompany" placeholder="Company Ltd"></div>\n    </div>\n    <div class="form-group"><label>Address</label><textarea id="cAddress" rows="2" placeholder="Business address"></textarea></div>\n    <div class="form-actions">\n      <button class="btn btn-outline" onclick="closeModal(\'clientOverlay\')">Cancel</button>\n      <button class="btn btn-green" onclick="saveClient()">Add Client</button>\n    </div>\n  </div>\n</div>\n\n<!-- Add Bank Account -->\n<div class="overlay" id="bankOverlay">\n  <div class="modal">\n    <h2>🏦 Add Bank Account</h2>\n    <div class="form-group"><label>Currency</label>\n      <select id="bCurrency">\n        <option value="NGN">🇳🇬 NGN — Nigerian Naira</option>\n        <option value="USD">🇺🇸 USD — US Dollar</option>\n        <option value="GBP">🇬🇧 GBP — British Pound</option>\n        <option value="EUR">🇪🇺 EUR — Euro</option>\n        <option value="GHS">🇬🇭 GHS — Ghanaian Cedi</option>\n        <option value="KES">🇰🇪 KES — Kenyan Shilling</option>\n        <option value="ZAR">🇿🇦 ZAR — South African Rand</option>\n      </select>\n    </div>\n    <div class="form-group"><label>Bank Name</label><input id="bName" placeholder="e.g. GTBank, UBA, Zenith…"></div>\n    <div class="form-row">\n      <div class="form-group"><label>Account Number</label><input id="bNum" placeholder="0123456789"></div>\n      <div class="form-group"><label>Account Name</label><input id="bAccName" placeholder="Name on account"></div>\n    </div>\n    <div class="form-row" id="intlBankFields" style="display:none">\n      <div class="form-group"><label>Routing / Sort Code</label><input id="bRouting" placeholder="Routing number"></div>\n      <div class="form-group"><label>SWIFT / BIC</label><input id="bSwift" placeholder="SWIFT code"></div>\n    </div>\n    <div class="form-group" id="ibanField" style="display:none"><label>IBAN</label><input id="bIban" placeholder="IBAN (EUR/GBP)"></div>\n    <div class="form-group" style="display:flex;align-items:center;gap:8px">\n      <input type="checkbox" id="bPrimary" style="width:auto">\n      <label for="bPrimary" style="font-size:13px;color:var(--text);text-transform:none;letter-spacing:0">Set as primary for this currency</label>\n    </div>\n    <div class="form-actions">\n      <button class="btn btn-outline" onclick="closeModal(\'bankOverlay\')">Cancel</button>\n      <button class="btn btn-green" onclick="saveBank()">Add Account</button>\n    </div>\n  </div>\n</div>\n\n<!-- Email Trail Modal -->\n<div class="overlay" id="emailTrailOverlay">\n  <div class="modal">\n    <h2>📬 Email Delivery History</h2>\n    <div id="emailTrailContent" style="min-height:80px"></div>\n    <div class="form-actions"><button class="btn btn-outline" onclick="closeModal(\'emailTrailOverlay\')">Close</button></div>\n  </div>\n</div>\n\n<!-- ═══════════════ SCRIPTS ═══════════════ -->\n<script>\nconst API = \'\';\nlet _user = null;\nlet _clients = [];\nlet _revenueChart = null;\nlet _lastInsightsTs = 0;\n\n// ── Init ──────────────────────────────────────────────────────────────────────\n(async function init(){\n  const token = localStorage.getItem(\'pp_token\');\n  const user  = localStorage.getItem(\'pp_user\');\n  if(!token){ location.href = \'/\'; return; }\n  if(user){ _user = JSON.parse(user); applyUser(_user); }\n\n  document.getElementById(\'pageDate\').textContent = new Date().toLocaleDateString(\'en-GB\',{weekday:\'long\',year:\'numeric\',month:\'long\',day:\'numeric\'});\n  try{\n    const r = await authFetch(\'/auth/me\');\n    if(r.ok){ _user = await r.json(); localStorage.setItem(\'pp_user\', JSON.stringify(_user)); applyUser(_user); }\n  }catch(e){}\n  loadOverview();\n  loadClientsDropdown();\n})();\n\nfunction applyUser(u){\n  document.getElementById(\'sideAvatar\').textContent = (u.name||\'?\')[0].toUpperCase();\n  document.getElementById(\'sideUsername\').textContent = u.business_name || u.name || \'User\';\n  document.getElementById(\'sidePlan\').textContent = (u.plan||\'free\').charAt(0).toUpperCase()+(u.plan||\'free\').slice(1)+\' Plan\';\n}\n\n// ── API helpers ───────────────────────────────────────────────────────────────\nfunction authFetch(url, opts={}){\n  opts.headers = opts.headers || {};\n  opts.headers[\'Authorization\'] = \'Bearer \'+localStorage.getItem(\'pp_token\');\n  if(opts.body && typeof opts.body === \'object\' && !(opts.body instanceof FormData)){\n    opts.headers[\'Content-Type\'] = \'application/json\';\n    opts.body = JSON.stringify(opts.body);\n  }\n  return fetch(API+url, opts);\n}\n\nfunction showAlert(msg, type=\'success\', el=\'alertBox\'){\n  const box = document.getElementById(el);\n  if(!box) return;\n  const icons = {success:\'✅\',error:\'❌\',info:\'ℹ️\',warn:\'⚠️\'};\n  box.innerHTML = `<div class="alert alert-${type}">${icons[type]||\'\'} ${msg}</div>`;\n  setTimeout(()=>box.innerHTML=\'\', 4000);\n}\n\nfunction fmt(amount, currency){\n  const c = currency||(_user&&_user.currency)||\'NGN\';\n  const sym = {NGN:\'₦\',USD:\'$\',GBP:\'£\',EUR:\'€\',GHS:\'₵\',KES:\'KSh\',ZAR:\'R\'};\n  return (sym[c]||c+\' \')+Number(amount||0).toLocaleString(\'en\',{minimumFractionDigits:0,maximumFractionDigits:0});\n}\n\nfunction badge(status){\n  const cls = \'badge badge-\'+(status||\'draft\').toLowerCase().replace(/\\s+/,\'-\');\n  return `<span class="${cls}">${(status||\'Draft\').charAt(0).toUpperCase()+(status||\'\').slice(1)}</span>`;\n}\n\nfunction fmtDate(d){ if(!d) return \'—\'; try{ return new Date(d).toLocaleDateString(\'en-GB\',{day:\'2-digit\',month:\'short\',year:\'2-digit\'}); }catch(e){ return d; } }\n\n// ── Navigation ────────────────────────────────────────────────────────────────\nfunction showPage(page){\n  document.querySelectorAll(\'.page\').forEach(p=>p.classList.remove(\'active\'));\n  document.querySelectorAll(\'.nav-item\').forEach(n=>n.classList.remove(\'active\'));\n  document.getElementById(\'page-\'+page).classList.add(\'active\');\n  event?.target?.closest(\'.nav-item\')?.classList?.add(\'active\');\n  // Fix: highlight correct nav item\n  document.querySelectorAll(\'.nav-item\').forEach(n=>{\n    if(n.getAttribute(\'onclick\')?.includes("\'"+page+"\'")) n.classList.add(\'active\');\n  });\n  const titles = {overview:\'Overview\',proposals:\'Proposals\',invoices:\'Invoices\',clients:\'Clients\',settings:\'Settings\'};\n  const actions = {overview:\'+ New Invoice\',proposals:\'+ New Proposal\',invoices:\'+ New Invoice\',clients:\'+ Add Client\',settings:\'\'};\n  document.getElementById(\'pageTitle\').textContent = titles[page]||page;\n  const btn = document.getElementById(\'topbarAction\');\n  if(actions[page]){ btn.textContent=actions[page]; btn.style.display=\'\'; }\n  else btn.style.display=\'none\';\n  if(page===\'overview\') loadOverview();\n  if(page===\'proposals\') loadProposals();\n  if(page===\'invoices\') loadInvoices();\n  if(page===\'clients\') loadClients();\n  if(page===\'settings\') loadSettings();\n}\n\nfunction topbarActionFn(){\n  const active = document.querySelector(\'.page.active\')?.id?.replace(\'page-\',\'\');\n  if(active===\'proposals\') openNewProposal();\n  else if(active===\'clients\') openNewClient();\n  else openNewInvoice();\n}\n\n// ── Overview ──────────────────────────────────────────────────────────────────\nasync function loadOverview(){\n  try{\n    const r = await authFetch(\'/dashboard/stats\');\n    if(!r.ok) return;\n    const d = await r.json();\n    document.getElementById(\'statsGrid\').innerHTML = `\n      <div class="stat-card"><div class="stat-label">Total Invoiced</div>\n        <div class="stat-value" style="color:var(--white)">${fmt(d.total_invoiced,d.currency)}</div>\n        <div class="stat-change" style="color:var(--muted)">${d.invoice_count} invoice${d.invoice_count!==1?\'s\':\'\'}</div></div>\n      <div class="stat-card"><div class="stat-label">Total Paid</div>\n        <div class="stat-value green">${fmt(d.total_paid,d.currency)}</div>\n        <div class="stat-change green">↑ ${d.collection_rate}% collection rate</div></div>\n      <div class="stat-card"><div class="stat-label">Pending</div>\n        <div class="stat-value yellow">${fmt(d.total_pending,d.currency)}</div>\n        <div class="stat-change" style="color:var(--muted)">${d.proposals_sent} proposals sent</div></div>\n      <div class="stat-card"><div class="stat-label">Overdue</div>\n        <div class="stat-value ${d.total_overdue>0?\'red\':\'green\'}">${fmt(d.total_overdue,d.currency)}</div>\n        <div class="stat-change ${d.overdue_count>0?\'red\':\'green\'}">${d.overdue_count} overdue invoice${d.overdue_count!==1?\'s\':\'\'}</div></div>`;\n    drawChart(d.monthly_revenue, d.currency);\n    document.getElementById(\'chartCurrency\').textContent = d.currency;\n    loadRecent();\n    loadInsights();\n  }catch(e){ console.error(e); }\n}\n\n// ── Revenue Chart ─────────────────────────────────────────────────────────────\nfunction drawChart(months, currency){\n  const canvas = document.getElementById(\'revenueChart\');\n  if(_revenueChart){ _revenueChart.destroy(); _revenueChart=null; }\n  const ctx = canvas.getContext(\'2d\');\n  const labels = months.map(m=>m.month);\n  const data   = months.map(m=>m.revenue);\n  const max    = Math.max(...data, 1);\n  _revenueChart = new Chart(ctx, {\n    type:\'bar\',\n    data:{\n      labels,\n      datasets:[{\n        label: \'Revenue (\'+currency+\')\',\n        data,\n        backgroundColor: data.map(v=>\n          v===max ? \'rgba(99,102,241,0.9)\' : \'rgba(99,102,241,0.35)\'),\n        borderColor: data.map(v=>\n          v===max ? \'#6366f1\' : \'rgba(99,102,241,0.5)\'),\n        borderWidth:1, borderRadius:5, borderSkipped:false,\n      }]\n    },\n    options:{\n      responsive:true, maintainAspectRatio:false,\n      plugins:{legend:{display:false},tooltip:{\n        backgroundColor:\'#1e293b\', titleColor:\'#e2e8f0\', bodyColor:\'#94a3b8\',\n        callbacks:{label:ctx=>\' \'+fmt(ctx.parsed.y, currency)}\n      }},\n      scales:{\n        x:{grid:{color:\'rgba(255,255,255,.04)\'},ticks:{color:\'#64748b\',font:{size:11}}},\n        y:{grid:{color:\'rgba(255,255,255,.04)\'},ticks:{color:\'#64748b\',font:{size:11},\n           callback:v=>fmt(v,currency)},beginAtZero:true}\n      }\n    }\n  });\n}\n\n// ── AI Insights ───────────────────────────────────────────────────────────────\nlet _insightsLoading = false;\nasync function loadInsights(force=false){\n  if(_insightsLoading) return;\n  const now = Date.now();\n  if(!force && now - _lastInsightsTs < 300000) return; // 5min cache\n  _insightsLoading = true;\n  const box = document.getElementById(\'aiInsights\');\n  box.innerHTML = \'<div class="skeleton sk-line"></div><div class="skeleton sk-line" style="width:80%"></div>\';\n  try{\n    const r = await authFetch(\'/dashboard/insights\');\n    if(r.ok){\n      const d = await r.json();\n      box.innerHTML = (d.insights||\'No insights available.\')\n        .replace(/\\n/g,\'<br>\')\n        .replace(/\\*\\*(.*?)\\*\\*/g,\'<strong style="color:#fff">$1</strong>\')\n        .replace(/\\*(.*?)\\*/g,\'<em style="color:#a5b4fc">$1</em>\');\n      _lastInsightsTs = Date.now();\n    }\n  }catch(e){ box.textContent=\'Could not load insights. Check your GROQ_API_KEY.\'; }\n  _insightsLoading = false;\n}\n\n// ── Recent Activity ───────────────────────────────────────────────────────────\nasync function loadRecent(){\n  try{\n    const r = await authFetch(\'/dashboard/recent\');\n    if(!r.ok) return;\n    const items = await r.json();\n    const tbody = document.getElementById(\'recentTable\');\n    if(!items.length){\n      tbody.innerHTML = `<tr><td colspan="5"><div class="empty"><div class="empty-icon">⚡</div><h3>Nothing yet</h3><p>Create your first invoice or proposal to get started.</p></div></td></tr>`;\n      return;\n    }\n    tbody.innerHTML = items.map(a=>`<tr>\n      <td>${a.type===\'invoice\'?\'🧾 Invoice\':\'📄 Proposal\'}</td>\n      <td style="color:var(--white);font-weight:600">${a.title}</td>\n      <td style="font-weight:700;color:var(--brand)">${fmt(a.amount,a.currency)}</td>\n      <td>${badge(a.status)}</td>\n      <td style="color:var(--muted)">${fmtDate(a.date)}</td>\n    </tr>`).join(\'\');\n  }catch(e){}\n}\n\n// ── Proposals ─────────────────────────────────────────────────────────────────\nlet _proposals = [];\nasync function loadProposals(){\n  try{\n    const r = await authFetch(\'/proposals\');\n    if(!r.ok) return;\n    _proposals = await r.json();\n    const tbody = document.getElementById(\'proposalTable\');\n    if(!_proposals.length){\n      tbody.innerHTML = `<tr><td colspan="6"><div class="empty"><div class="empty-icon">📄</div>\n        <h3>No proposals yet</h3><p>Click "+ New Proposal" to create your first AI-powered proposal.</p>\n        <button class="btn btn-primary btn-sm" onclick="openNewProposal()">+ New Proposal</button>\n      </div></td></tr>`;\n      return;\n    }\n    tbody.innerHTML = _proposals.map(p=>`<tr>\n      <td style="font-weight:600;color:var(--white)">${p.title}</td>\n      <td style="color:var(--muted)">${p.client_id?\'Client\':\'-\'}</td>\n      <td style="font-weight:700;color:var(--brand)">${fmt(p.total_amount,p.currency)}</td>\n      <td>${badge(p.status)}</td>\n      <td style="color:var(--muted)">${fmtDate(p.created_at)}</td>\n      <td><div class="td-actions">\n        ${p.status!==\'accepted\'?`<button class="btn btn-sm btn-primary btn-xs" onclick="sendProposal(\'${p.id}\',\'${p.title.replace(/\'/g,"\\\\\'")}\')">Send</button>`:\'\'}\n        <button class="btn btn-sm btn-red btn-xs" onclick="deleteProposal(\'${p.id}\')">✕</button>\n      </div></td>\n    </tr>`).join(\'\');\n  }catch(e){}\n}\n\nasync function sendProposal(id, title){\n  if(!confirm(`Send proposal "${title}"?`)) return;\n  try{\n    const r = await authFetch(`/proposals/${id}/send`,{method:\'POST\'});\n    const d = await r.json();\n    showAlert(d.message||\'Proposal sent!\',\'success\',\'propAlert\');\n    loadProposals();\n  }catch(e){ showAlert(\'Failed to send\',\'error\',\'propAlert\'); }\n}\n\nasync function deleteProposal(id){\n  if(!confirm(\'Delete this proposal?\')) return;\n  try{\n    await authFetch(`/proposals/${id}`,{method:\'DELETE\'});\n    loadProposals();\n  }catch(e){}\n}\n\n// ── Invoices ──────────────────────────────────────────────────────────────────\nlet _invoices = [];\nasync function loadInvoices(){\n  try{\n    const status = document.getElementById(\'invFilter\')?.value||\'\';\n    const r = await authFetch(\'/invoices\'+(status?\'?status=\'+status:\'\'));\n    if(!r.ok) return;\n    _invoices = await r.json();\n    const tbody = document.getElementById(\'invoiceTable\');\n    if(!_invoices.length){\n      tbody.innerHTML = `<tr><td colspan="7"><div class="empty"><div class="empty-icon">🧾</div>\n        <h3>No invoices yet</h3><p>Click "+ New Invoice" to send your first invoice and get paid.</p>\n        <button class="btn btn-primary btn-sm" onclick="openNewInvoice()">+ New Invoice</button>\n      </div></td></tr>`;\n      return;\n    }\n    // Check overdue\n    const today = new Date();\n    tbody.innerHTML = _invoices.map(inv=>{\n      const isOverdue = inv.due_date && inv.status!==\'paid\' && new Date(inv.due_date)<today;\n      const status = isOverdue && inv.status!==\'paid\' ? \'overdue\' : inv.status;\n      const emailStatus = inv.email_status;\n      return `<tr>\n        <td style="font-family:monospace;font-size:12px;color:var(--brand)">${inv.invoice_number}</td>\n        <td style="font-weight:600;color:var(--white)">${inv.client_name||inv.title||\'—\'}</td>\n        <td style="font-weight:700;color:var(--brand)">${fmt(inv.total,inv.currency)}</td>\n        <td style="color:${isOverdue?\'var(--red)\':\'var(--muted)\'}">${fmtDate(inv.due_date)}</td>\n        <td>${badge(status)}</td>\n        <td>\n          <button class="btn btn-xs btn-outline" onclick="showEmailTrail(\'${inv.id}\')" title="View email history">\n            📬\n          </button>\n        </td>\n        <td><div class="td-actions">\n          ${inv.status===\'draft\'?`<button class="btn btn-xs btn-primary" onclick="sendInvoice(\'${inv.id}\',\'${(inv.client_name||\'\').replace(/\'/g,"\\\\\'")}\')">Send</button>`:\'\'}\n          ${inv.status!==\'paid\'?`<button class="btn btn-xs btn-yellow" onclick="sendReminder(\'${inv.id}\',\'${(inv.client_name||\'\').replace(/\'/g,"\\\\\'")}\')">Remind</button>`:\'\'}\n          ${inv.status!==\'paid\'?`<button class="btn btn-xs btn-green" onclick="markPaid(\'${inv.id}\')">Paid ✓</button>`:\'\'}\n          <button class="btn btn-xs btn-outline" onclick="downloadPDF(\'${inv.id}\',\'${inv.invoice_number}\')">PDF</button>\n          ${inv.status===\'paid\'?`<button class="btn btn-xs btn-outline" onclick="downloadReceipt(\'${inv.id}\',\'${inv.invoice_number}\')">Receipt</button>`:\'\'}\n          <button class="btn btn-xs btn-red" onclick="deleteInvoice(\'${inv.id}\')">✕</button>\n        </div></td>\n      </tr>`;\n    }).join(\'\');\n  }catch(e){ console.error(e); }\n}\n\nasync function sendInvoice(id, clientName){\n  if(!confirm(`Send invoice to ${clientName||\'client\'}?`)) return;\n  try{\n    const r = await authFetch(`/invoices/${id}/send`,{method:\'POST\'});\n    const d = await r.json();\n    if(d.success){\n      showAlert(`${d.message} · Email: ${d.email_provider}`,\'success\',\'invAlert\');\n      if(d.payment_url) copyLink(d.payment_url);\n    } else showAlert(\'Send failed\',\'error\',\'invAlert\');\n    loadInvoices();\n  }catch(e){ showAlert(\'Error sending invoice\',\'error\',\'invAlert\'); }\n}\n\nasync function sendReminder(id, name){\n  if(!confirm(`Send AI reminder to ${name||\'client\'}?`)) return;\n  try{\n    const r = await authFetch(`/invoices/${id}/remind`,{method:\'POST\'});\n    const d = await r.json();\n    showAlert(d.message||\'Reminder sent!\',\'success\',\'invAlert\');\n  }catch(e){ showAlert(\'Error\',\'error\',\'invAlert\'); }\n}\n\nasync function markPaid(id){\n  if(!confirm(\'Mark this invoice as paid?\')) return;\n  const r = await authFetch(`/invoices/${id}/mark-paid`,{method:\'POST\'});\n  if(r.ok) loadInvoices();\n}\n\nasync function deleteInvoice(id){\n  if(!confirm(\'Delete this invoice? This cannot be undone.\')) return;\n  const r = await authFetch(`/invoices/${id}`,{method:\'DELETE\'});\n  if(r.ok) loadInvoices();\n}\n\nasync function showEmailTrail(invoiceId){\n  openModal(\'emailTrailOverlay\');\n  const box = document.getElementById(\'emailTrailContent\');\n  box.innerHTML = \'<div class="skeleton sk-line"></div><div class="skeleton sk-line" style="width:70%"></div>\';\n  try{\n    const r = await authFetch(`/invoices/${invoiceId}/emails`);\n    const logs = await r.json();\n    if(!logs.length){\n      box.innerHTML = \'<div class="empty" style="padding:32px"><div class="empty-icon">📭</div><h3>No emails sent yet</h3><p>Send the invoice to see delivery history here.</p></div>\';\n      return;\n    }\n    const colors = {sent:\'#34d399\',failed:\'#f87171\',queued:\'#94a3b8\',delivered:\'#10b981\',opened:\'#6366f1\'};\n    box.innerHTML = logs.map(l=>`\n      <div class="email-item">\n        <div class="email-dot" style="background:${colors[l.status]||\'#94a3b8\'}"></div>\n        <div style="flex:1">\n          <div style="font-weight:600;color:var(--white)">${l.type.charAt(0).toUpperCase()+l.type.slice(1)}</div>\n          <div style="color:var(--muted)">${l.to} · ${fmtDate(l.sent_at)}</div>\n        </div>\n        <span class="badge badge-${l.status}">${l.status}</span>\n      </div>`).join(\'\');\n  }catch(e){ box.textContent=\'Failed to load email history.\'; }\n}\n\n// ── PDF / Receipt ─────────────────────────────────────────────────────────────\nasync function downloadPDF(invoiceId, invNum){\n  try{\n    const r = await authFetch(`/invoices/${invoiceId}/pdf`);\n    if(!r.ok){ showAlert(\'Could not generate PDF\',\'error\',\'invAlert\'); return; }\n    const blob = await r.blob();\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement(\'a\');\n    a.href=url; a.download=`${invNum}.pdf`; a.click();\n    URL.revokeObjectURL(url);\n  }catch(e){ showAlert(\'PDF error: \'+e.message,\'error\',\'invAlert\'); }\n}\n\nasync function downloadReceipt(invoiceId, invNum){\n  try{\n    const r = await authFetch(`/invoices/${invoiceId}/receipt`);\n    if(!r.ok){ showAlert(\'Could not generate receipt\',\'error\',\'invAlert\'); return; }\n    const blob = await r.blob();\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement(\'a\');\n    a.href=url; a.download=`Receipt-${invNum}.pdf`; a.click();\n    URL.revokeObjectURL(url);\n  }catch(e){ showAlert(\'Receipt error: \'+e.message,\'error\',\'invAlert\'); }\n}\n\n// ── Clients ───────────────────────────────────────────────────────────────────\nlet _clientsList = [];\nasync function loadClientsDropdown(){\n  try{\n    const r = await authFetch(\'/clients\');\n    if(!r.ok) return;\n    _clientsList = await r.json();\n    [\'pClient\',\'iClient\'].forEach(id=>{\n      const sel = document.getElementById(id);\n      if(!sel) return;\n      const cur = sel.value;\n      sel.innerHTML = \'<option value="">— Select client —</option>\'+\n        _clientsList.map(c=>`<option value="${c.id}">${c.name} (${c.email})</option>`).join(\'\');\n      if(cur) sel.value = cur;\n    });\n  }catch(e){}\n}\n\nasync function loadClients(){\n  try{\n    const r = await authFetch(\'/clients\');\n    if(!r.ok) return;\n    _clientsList = await r.json();\n    const tbody = document.getElementById(\'clientTable\');\n    if(!_clientsList.length){\n      tbody.innerHTML = `<tr><td colspan="6"><div class="empty"><div class="empty-icon">👥</div>\n        <h3>No clients yet</h3><p>Add your first client to start sending proposals and invoices.</p>\n        <button class="btn btn-primary btn-sm" onclick="openNewClient()">+ Add Client</button>\n      </div></td></tr>`;\n      return;\n    }\n    tbody.innerHTML = _clientsList.map(c=>`<tr>\n      <td style="font-weight:700;color:var(--white)">${c.name}</td>\n      <td style="color:var(--muted)">${c.email}</td>\n      <td style="color:var(--muted)">${c.phone||\'—\'}</td>\n      <td style="color:var(--muted)">${c.company||\'—\'}</td>\n      <td style="color:var(--muted)">${fmtDate(c.created_at)}</td>\n      <td><button class="btn btn-xs btn-red" onclick="deleteClient(\'${c.id}\')">✕</button></td>\n    </tr>`).join(\'\');\n  }catch(e){}\n}\n\nasync function saveClient(){\n  const name=document.getElementById(\'cName\').value.trim();\n  const email=document.getElementById(\'cEmail\').value.trim();\n  if(!name||!email){ showAlert(\'Name and email are required\',\'error\',\'clientAlert\'); return; }\n  try{\n    const r = await authFetch(\'/clients\',{method:\'POST\',body:{\n      name,email,phone:document.getElementById(\'cPhone\').value,\n      company:document.getElementById(\'cCompany\').value,\n      address:document.getElementById(\'cAddress\').value\n    }});\n    const d = await r.json();\n    closeModal(\'clientOverlay\');\n    showAlert(\'Client added!\',\'success\',\'clientAlert\');\n    [\'cName\',\'cEmail\',\'cPhone\',\'cCompany\',\'cAddress\'].forEach(id=>document.getElementById(id).value=\'\');\n    loadClients(); loadClientsDropdown();\n  }catch(e){ showAlert(\'Error adding client\',\'error\',\'clientAlert\'); }\n}\n\nasync function deleteClient(id){\n  if(!confirm(\'Delete this client?\')) return;\n  const r = await authFetch(`/clients/${id}`,{method:\'DELETE\'});\n  if(r.ok){ showAlert(\'Client removed\',\'success\',\'clientAlert\'); loadClients(); loadClientsDropdown(); }\n}\n\n// ── Invoice form ──────────────────────────────────────────────────────────────\nlet _itemCount = 0;\nfunction openNewInvoice(){\n  _itemCount=0;\n  document.getElementById(\'itemRows\').innerHTML=\'\';\n  document.getElementById(\'invTotal\').textContent=\'—\';\n  [\'iTitle\',\'iNotes\'].forEach(id=>document.getElementById(id).value=\'\');\n  document.getElementById(\'iTax\').value=\'0\';\n  document.getElementById(\'iDiscount\').value=\'0\';\n  const due = new Date(); due.setDate(due.getDate()+14);\n  document.getElementById(\'iDue\').value = due.toISOString().split(\'T\')[0];\n  if(_user) document.getElementById(\'iCurrency\').value = _user.currency||\'NGN\';\n  addItem();\n  openModal(\'invoiceOverlay\');\n}\n\nfunction addItem(){\n  _itemCount++;\n  const div = document.createElement(\'div\');\n  div.className=\'item-row\'; div.id=\'item-\'+_itemCount;\n  div.innerHTML=`\n    <input placeholder="Description" class="item-desc" oninput="calcTotal()">\n    <input type="number" placeholder="Qty" value="1" min="0.01" step="0.01" class="item-qty" oninput="calcTotal()">\n    <input type="number" placeholder="Unit price" min="0" step="0.01" class="item-price" oninput="calcTotal()">\n    <button class="remove-btn" onclick="document.getElementById(\'item-${_itemCount}\').remove();calcTotal()">✕</button>`;\n  document.getElementById(\'itemRows\').appendChild(div);\n  div.querySelector(\'.item-desc\').focus();\n}\n\nfunction calcTotal(){\n  const rows = document.querySelectorAll(\'#itemRows .item-row\');\n  let sub=0;\n  rows.forEach(r=>{\n    const q = parseFloat(r.querySelector(\'.item-qty\').value)||0;\n    const p = parseFloat(r.querySelector(\'.item-price\').value)||0;\n    sub += q*p;\n  });\n  const tax = parseFloat(document.getElementById(\'iTax\').value)||0;\n  const disc = parseFloat(document.getElementById(\'iDiscount\').value)||0;\n  const total = sub + sub*(tax/100) - disc;\n  const cur = document.getElementById(\'iCurrency\').value||(_user?.currency)||\'NGN\';\n  document.getElementById(\'invTotal\').textContent = fmt(total,cur);\n  return {rows, sub, tax, disc, total};\n}\n\nasync function saveInvoice(){\n  const rows = document.querySelectorAll(\'#itemRows .item-row\');\n  const items = [];\n  rows.forEach(r=>{\n    const d = r.querySelector(\'.item-desc\').value.trim();\n    const q = parseFloat(r.querySelector(\'.item-qty\').value)||1;\n    const p = parseFloat(r.querySelector(\'.item-price\').value)||0;\n    if(d) items.push({description:d,quantity:q,unit_price:p});\n  });\n  if(!items.length){ showAlert(\'Add at least one line item\',\'error\',\'invAlert\'); return; }\n  try{\n    const r = await authFetch(\'/invoices\',{method:\'POST\',body:{\n      client_id:document.getElementById(\'iClient\').value||null,\n      title:document.getElementById(\'iTitle\').value,\n      items,\n      tax_rate:parseFloat(document.getElementById(\'iTax\').value)||0,\n      discount:parseFloat(document.getElementById(\'iDiscount\').value)||0,\n      currency:document.getElementById(\'iCurrency\').value||\'NGN\',\n      due_date:document.getElementById(\'iDue\').value,\n      notes:document.getElementById(\'iNotes\').value,\n      auto_reminders:true\n    }});\n    const d = await r.json();\n    if(d.invoice_number){\n      closeModal(\'invoiceOverlay\');\n      showAlert(`Invoice ${d.invoice_number} created!`,\'success\',\'invAlert\');\n      showPage(\'invoices\'); loadInvoices();\n    } else showAlert(JSON.stringify(d),\'error\',\'invAlert\');\n  }catch(e){ showAlert(\'Error: \'+e.message,\'error\',\'invAlert\'); }\n}\n\n// ── Proposal form ─────────────────────────────────────────────────────────────\nlet _aiProposalData = null;\nfunction openNewProposal(){\n  document.getElementById(\'aiProposalResult\').style.display=\'none\';\n  document.getElementById(\'aiProposalResult\').textContent=\'\';\n  document.getElementById(\'savePropBtn\').disabled=true;\n  _aiProposalData=null;\n  openModal(\'proposalOverlay\');\n}\n\nasync function generateAIProposal(){\n  const service = document.getElementById(\'pService\').value.trim();\n  const scope   = document.getElementById(\'pScope\').value.trim();\n  if(!service||!scope){ showAlert(\'Fill service type and scope\',\'warn\',\'propAlert\'); return; }\n  const btn = document.getElementById(\'aiGenBtn\');\n  btn.textContent=\'⏳ Generating…\'; btn.disabled=true;\n  const box = document.getElementById(\'aiProposalResult\');\n  box.style.display=\'block\'; box.textContent=\'Writing your proposal…\';\n  try{\n    const r = await authFetch(\'/proposals/ai-draft\',{method:\'POST\',body:{\n      client_id:document.getElementById(\'pClient\').value||null,\n      service_type:service, scope,\n      budget:document.getElementById(\'pBudget\').value,\n      tone:document.getElementById(\'pTone\').value\n    }});\n    const d = await r.json();\n    _aiProposalData = d;\n    box.innerHTML = (d.content||\'\').replace(/\\n/g,\'<br>\');\n    document.getElementById(\'savePropBtn\').disabled=false;\n  }catch(e){ box.textContent=\'AI unavailable. Check GROQ_API_KEY.\'; }\n  btn.textContent=\'✨ Generate with AI\'; btn.disabled=false;\n}\n\nasync function saveAIProposal(){\n  if(!_aiProposalData){ showAlert(\'Generate a proposal first\',\'warn\',\'propAlert\'); return; }\n  try{\n    const r = await authFetch(\'/proposals\',{method:\'POST\',body:{\n      title:_aiProposalData.title||(document.getElementById(\'pService\').value+\' Proposal\'),\n      client_id:document.getElementById(\'pClient\').value||null,\n      content:_aiProposalData.content,\n      services:_aiProposalData.services||[],\n      total_amount:_aiProposalData.suggested_total||0,\n      currency:(_user?.currency)||\'NGN\',\n    }});\n    const d = await r.json();\n    closeModal(\'proposalOverlay\');\n    showAlert(\'Proposal saved! Open Proposals to send it.\',\'success\',\'propAlert\');\n    loadProposals();\n  }catch(e){ showAlert(\'Save error\',\'error\',\'propAlert\'); }\n}\n\n// ── Settings ──────────────────────────────────────────────────────────────────\nfunction switchSettingsTab(tab){\n  [\'profile\',\'banks\',\'plan\'].forEach(t=>{\n    document.getElementById(\'settingsTab-\'+t).style.display = t===tab?\'block\':\'none\';\n    const btn = document.getElementById(\'stab-\'+t);\n    btn.className = t===tab ? \'btn btn-primary btn-sm\' : \'btn btn-outline btn-sm\';\n  });\n  if(tab===\'banks\') loadBankAccounts();\n  if(tab===\'plan\') loadPlanInfo();\n}\n\nasync function loadSettings(){\n  try{\n    const r = await authFetch(\'/auth/me\');\n    if(!r.ok) return;\n    const u = await r.json(); _user=u;\n    document.getElementById(\'pName\').value = u.name||\'\';\n    document.getElementById(\'pBusiness\').value = u.business_name||\'\';\n    document.getElementById(\'pPhone\').value = u.phone||\'\';\n    document.getElementById(\'pCountry\').value = u.country||\'Nigeria\';\n    document.getElementById(\'pCurrency\').value = u.currency||\'NGN\';\n    document.getElementById(\'pEmail\').value = u.email||\'\';\n  }catch(e){}\n}\n\nasync function saveProfile(){\n  try{\n    const r = await authFetch(\'/auth/profile\',{method:\'PUT\',body:{\n      name:document.getElementById(\'pName\').value,\n      business_name:document.getElementById(\'pBusiness\').value,\n      phone:document.getElementById(\'pPhone\').value,\n      country:document.getElementById(\'pCountry\').value,\n      currency:document.getElementById(\'pCurrency\').value,\n    }});\n    const d = await r.json();\n    showAlert(\'Profile saved!\',\'success\',\'settingsAlert\');\n    if(_user){ _user.currency=document.getElementById(\'pCurrency\').value; }\n  }catch(e){ showAlert(\'Save error\',\'error\',\'settingsAlert\'); }\n}\n\n// ── Bank Accounts ─────────────────────────────────────────────────────────────\nconst CURRENCY_FLAGS = {NGN:\'🇳🇬\',USD:\'🇺🇸\',GBP:\'🇬🇧\',EUR:\'🇪🇺\',GHS:\'🇬🇭\',KES:\'🇰🇪\',ZAR:\'🇿🇦\'};\nlet _banks = [];\n\nasync function loadBankAccounts(){\n  const grid = document.getElementById(\'bankGrid\');\n  try{\n    const r = await authFetch(\'/banks\');\n    const d = await r.json();\n    _banks = d.banks||[];\n    if(!_banks.length){\n      grid.innerHTML=`<div style="grid-column:1/-1"><div class="empty" style="padding:40px">\n        <div class="empty-icon">🏦</div><h3>No bank accounts yet</h3>\n        <p>Add accounts for each currency. Clients see the right bank on their invoice automatically.</p>\n        <button class="btn btn-primary btn-sm" onclick="openAddBank()">+ Add Bank Account</button>\n      </div></div>`;\n      return;\n    }\n    grid.innerHTML = _banks.map(b=>`\n      <div class="bank-card ${b.is_primary?\'primary\':\'\'}">\n        <div class="bank-card-currency">${CURRENCY_FLAGS[b.currency]||\'\'} ${b.currency}\n          ${b.is_primary?\'<span class="badge badge-paid" style="margin-left:4px">Primary</span>\':\'\'}\n        </div>\n        <div class="bank-card-name">${b.bank_name}</div>\n        <div class="bank-card-num">${b.account_name}</div>\n        <div class="bank-card-num" style="font-family:monospace">••••${b.account_number.slice(-4)}</div>\n        <div style="display:flex;gap:6px;margin-top:10px">\n          ${!b.is_primary?`<button class="btn btn-xs btn-outline" onclick="setPrimaryBank(\'${b.id}\')">Set Primary</button>`:\'\'}\n          <button class="btn btn-xs btn-red" onclick="deleteBank(\'${b.id}\')">Remove</button>\n        </div>\n      </div>`).join(\'\');\n  }catch(e){ grid.innerHTML=\'<p style="color:var(--red)">Failed to load bank accounts.</p>\'; }\n}\n\nfunction openAddBank(){\n  const c = document.getElementById(\'bCurrency\').value;\n  const intl = [\'USD\',\'GBP\'].includes(c);\n  const eur  = c===\'EUR\';\n  document.getElementById(\'intlBankFields\').style.display = intl||eur?\'grid\':\'none\';\n  document.getElementById(\'ibanField\').style.display = eur||c===\'GBP\'?\'block\':\'none\';\n  openModal(\'bankOverlay\');\n}\n\ndocument.getElementById(\'bCurrency\')?.addEventListener(\'change\',function(){\n  const c = this.value;\n  document.getElementById(\'intlBankFields\').style.display = [\'USD\',\'GBP\',\'EUR\'].includes(c)?\'grid\':\'none\';\n  document.getElementById(\'ibanField\').style.display = [\'EUR\',\'GBP\'].includes(c)?\'block\':\'none\';\n});\n\nasync function saveBank(){\n  const name = document.getElementById(\'bName\').value.trim();\n  const num  = document.getElementById(\'bNum\').value.trim();\n  const aname= document.getElementById(\'bAccName\').value.trim();\n  if(!name||!num||!aname){ showAlert(\'Bank name, account number and account name are required\',\'error\',\'settingsAlert\'); return; }\n  try{\n    const r = await authFetch(\'/banks\',{method:\'POST\',body:{\n      currency:document.getElementById(\'bCurrency\').value,\n      bank_name:name,account_number:num,account_name:aname,\n      routing_number:document.getElementById(\'bRouting\')?.value||null,\n      swift_code:document.getElementById(\'bSwift\')?.value||null,\n      iban:document.getElementById(\'bIban\')?.value||null,\n      is_primary:document.getElementById(\'bPrimary\').checked,\n    }});\n    const d = await r.json();\n    closeModal(\'bankOverlay\');\n    showAlert(\'Bank account added!\',\'success\',\'settingsAlert\');\n    loadBankAccounts();\n  }catch(e){ showAlert(\'Error: \'+e.message,\'error\',\'settingsAlert\'); }\n}\n\nasync function setPrimaryBank(id){\n  await authFetch(`/banks/${id}`,{method:\'PUT\',body:{is_primary:true}});\n  loadBankAccounts();\n}\n\nasync function deleteBank(id){\n  if(!confirm(\'Remove this bank account?\')) return;\n  const r = await authFetch(`/banks/${id}`,{method:\'DELETE\'});\n  if(r.ok) loadBankAccounts();\n}\n\n// ── Plan ──────────────────────────────────────────────────────────────────────\nasync function loadPlanInfo(){\n  const desc = document.getElementById(\'planDesc\');\n  const plan = _user?.plan||\'free\';\n  const limits = {free:\'3 invoices, 3 proposals, 5 clients\',solo:\'50 invoices, 50 proposals, 50 clients\',agency:\'Unlimited everything\',enterprise:\'Unlimited + enterprise support\'};\n  desc.textContent = `You are on the ${plan.charAt(0).toUpperCase()+plan.slice(1)} plan. ${limits[plan]||\'\'}`;\n}\n\nasync function upgradePlan(plan){\n  try{\n    const r = await authFetch(\'/billing/subscribe\',{method:\'POST\',body:{plan}});\n    const d = await r.json();\n    if(d.payment_url) window.open(d.payment_url,\'_blank\');\n    else showAlert(d.message||\'Contact support to upgrade\',\'info\',\'settingsAlert\');\n  }catch(e){}\n}\n\n// ── Utils ─────────────────────────────────────────────────────────────────────\nfunction openModal(id){ document.getElementById(id).classList.add(\'open\'); }\nfunction closeModal(id){ document.getElementById(id).classList.remove(\'open\'); }\nfunction copyLink(url){\n  navigator.clipboard?.writeText(url).catch(()=>{});\n  showAlert(\'Payment link copied to clipboard!\',\'info\',\'invAlert\');\n}\nfunction logout(){\n  localStorage.removeItem(\'pp_token\');\n  localStorage.removeItem(\'pp_user\');\n  location.href=\'/\';\n}\n\n// Close modals on backdrop click\ndocument.querySelectorAll(\'.overlay\').forEach(o=>o.addEventListener(\'click\',function(e){ if(e.target===this) this.classList.remove(\'open\'); }));\n</script>\n</body>\n</html>\n'

